  };

  const navTo = (view: View) => {
    setEditingExchange(null);
    setSigningExchange(null);
    setCurrentView(view);
    setIsMobileMenuOpen(false);
  };

  const toggleTheme = () => {
    setTheme(prev => prev === 'light' ? 'dark' : 'light');
  };

  const toggleSidebar = () => {
    setIsSidebarVisible(!isSidebarVisible);
  };

  return (
    <div className="flex flex-col lg:flex-row min-h-screen bg-sky-50 dark:bg-dracula-bg text-slate-900 dark:text-dracula-fg font-sans transition-colors duration-200">
      {/* Mobile Top Header */}
      <header className="lg:hidden bg-slate-900 dark:bg-dracula-darker text-white p-4 flex items-center justify-between sticky top-0 z-[60] shadow-md">
        <div className="flex items-center gap-2">
          <div className="w-8 h-8 bg-dracula-purple rounded-lg flex items-center justify-center">
            <HardDrive className="text-white" size={16} />
          </div>
          <h1 className="text-lg font-bold tracking-tight">AssetFlow</h1>
        </div>
        <div className="flex items-center gap-2">
          <button 
            onClick={toggleTheme}
            className="p-2 hover:bg-slate-800 dark:hover:bg-dracula-current rounded-lg transition-colors text-slate-300"
          >
            {theme === 'light' ? <Moon size={20} /> : <Sun size={20} />}
          </button>
          <button 
            onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
            className="p-2 hover:bg-slate-800 dark:hover:bg-dracula-current rounded-lg transition-colors"
          >
            {isMobileMenuOpen ? <X size={24} /> : <Menu size={24} />}
          </button>
        </div>
      </header>

      {/* Sidebar Overlay for Mobile */}
      {(isMobileMenuOpen) && (
        <div 
          className="fixed inset-0 bg-slate-900/60 dark:bg-dracula-darker/80 backdrop-blur-sm z-50 lg:hidden"
          onClick={() => setIsMobileMenuOpen(false)}
        />
      )}

      {/* Sidebar Component */}
      <aside className={`fixed inset-y-0 left-0 w-72 bg-slate-900 dark:bg-dracula-darker text-white flex-shrink-0 flex flex-col shadow-2xl z-[55] transition-all duration-300 transform lg:relative ${isMobileMenuOpen ? 'translate-x-0' : (isSidebarVisible ? 'translate-x-0' : '-translate-x-full lg:w-0 lg:opacity-0')} ${!isSidebarVisible && 'lg:hidden'}`}>
        <div className="p-8 hidden lg:flex items-center justify-between gap-3">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-dracula-purple rounded-xl flex items-center justify-center shadow-lg shadow-dracula-purple/20">
              <HardDrive className="text-white" size={20} />
            </div>
            <div>
              <h1 className="text-xl font-bold tracking-tight text-white">AssetFlow</h1>
              <span className="text-[10px] text-dracula-cyan font-bold tracking-widest uppercase">
                {logoPref === 'cirion' ? 'Cirion TI' : 'Admin'}
              </span>
            </div>
          </div>
          <button 
            onClick={toggleSidebar}
            className="p-1.5 hover:bg-slate-800 dark:hover:bg-dracula-current rounded-lg transition-colors text-slate-500 hover:text-white"
            title="Recolher Menu (Modo Foco)"
          >
            <PanelLeftClose size={18} />
          </button>
        </div>

        <nav className="flex-1 px-4 space-y-2 py-4 mt-16 lg:mt-0">
          <button
            disabled={isLoading}
            onClick={() => navTo('form')}
            className={`w-full flex items-center gap-4 px-4 py-3 rounded-xl transition-all duration-200 ${currentView === 'form' ? 'bg-dracula-purple text-white shadow-lg shadow-dracula-purple/20' : 'text-slate-400 dark:text-dracula-comment hover:bg-slate-800 dark:hover:bg-dracula-current hover:text-white disabled:opacity-50'}`}
          >
            <PlusCircle size={20} />
            <span className="font-semibold text-sm">Nova Troca</span>
          </button>

          <button
            disabled={isLoading}
            onClick={() => navTo('inventory')}
            className={`w-full flex items-center gap-4 px-4 py-3 rounded-xl transition-all duration-200 ${currentView === 'inventory' ? 'bg-dracula-purple text-white shadow-lg shadow-dracula-purple/20' : 'text-slate-400 dark:text-dracula-comment hover:bg-slate-800 dark:hover:bg-dracula-current hover:text-white disabled:opacity-50'}`}
          >
            <ClipboardList size={20} />
            <span className="font-semibold text-sm">InventĂĄrio</span>
          </button>

          <button
            disabled={isLoading}
            onClick={() => navTo('inbox')}
            className={`w-full flex items-center gap-4 px-4 py-3 rounded-xl transition-all duration-200 relative ${currentView === 'inbox' ? 'bg-dracula-purple text-white shadow-lg shadow-dracula-purple/20' : 'text-slate-400 dark:text-dracula-comment hover:bg-slate-800 dark:hover:bg-dracula-current hover:text-white disabled:opacity-50'}`}
          >
            <Mail size={20} />
            <span className="font-semibold text-sm">Outlook Mock</span>
            {emails.some(e => !e.read) && (
              <span className="absolute right-4 top-1/2 -translate-y-1/2 w-2.5 h-2.5 bg-dracula-pink rounded-full border-2 border-slate-900 dark:border-dracula-darker"></span>
            )}
          </button>
        </nav>

        {/* Configuration Footer Menu */}
        <div className="px-4 py-6 border-t border-slate-800 dark:border-dracula-current space-y-6">
          {/* Logo Selection */}
          <div className="space-y-3">
            <div className="flex items-center gap-2 text-[10px] text-slate-500 dark:text-dracula-comment uppercase font-bold tracking-widest ml-2">
              <ImageIcon size={12} /> Config. Logotipo
            </div>
            <div className="grid grid-cols-1 gap-1">
              <button 
                onClick={() => { setLogoPref('cirion'); if(window.innerWidth < 1024) setIsMobileMenuOpen(false); }}
                className={`text-left px-4 py-2.5 rounded-lg text-xs font-bold transition-all ${logoPref === 'cirion' ? 'bg-slate-800 dark:bg-dracula-current text-dracula-cyan' : 'text-slate-500 hover:text-slate-300'}`}
              >
                Cirion Technologies
              </button>
              <button 
                onClick={() => { setLogoPref('none'); if(window.innerWidth < 1024) setIsMobileMenuOpen(false); }}
                className={`text-left px-4 py-2.5 rounded-lg text-xs font-bold transition-all ${logoPref === 'none' ? 'bg-slate-800 dark:bg-dracula-current text-dracula-cyan' : 'text-slate-500 hover:text-slate-300'}`}
              >
                Sem Logotipo
              </button>
            </div>
          </div>

          {/* Theme Selection */}
          <div className="space-y-3">
            <div className="flex items-center gap-2 text-[10px] text-slate-500 dark:text-dracula-comment uppercase font-bold tracking-widest ml-2">
              {theme === 'light' ? <Moon size={12} /> : <Sun size={12} />} Tema Visual
            </div>
            <div className="flex p-1 bg-slate-800 dark:bg-dracula-bg rounded-xl border border-slate-700 dark:border-dracula-current">
              <button 
                onClick={() => setTheme('light')}
                className={`flex-1 flex items-center justify-center gap-2 py-2 rounded-lg text-[10px] font-bold transition-all ${theme === 'light' ? 'bg-slate-700 dark:bg-dracula-current text-white' : 'text-slate-500 hover:text-slate-300'}`}
              >
                <Sun size={12} /> Claro
              </button>
              <button 
                onClick={() => setTheme('dark')}
                className={`flex-1 flex items-center justify-center gap-2 py-2 rounded-lg text-[10px] font-bold transition-all ${theme === 'dark' ? 'bg-slate-700 dark:bg-dracula-current text-white' : 'text-slate-500 hover:text-slate-300'}`}
              >
                <Moon size={12} /> Dracula
              </button>
            </div>
          </div>
        </div>

        <div className="p-4 border-t border-slate-800 dark:border-dracula-current">
          <button className="w-full flex items-center gap-4 px-4 py-3 text-slate-500 dark:text-dracula-comment hover:text-dracula-red transition-colors">
            <LogOut size={20} />
            <span className="font-semibold text-sm">Sair</span>
          </button>
        </div>
      </aside>

      <main className={`flex-1 overflow-x-hidden overflow-y-auto p-4 md:p-10 relative transition-all duration-300 ${!isSidebarVisible ? 'lg:pl-10' : ''}`}>
        {/* Toggle Sidebar Button (Floating when hidden) */}
        {!isSidebarVisible && (
          <button 
            onClick={toggleSidebar}
            className="hidden lg:flex fixed left-6 top-8 z-[60] p-2 bg-slate-900 dark:bg-dracula-purple text-white rounded-xl shadow-2xl hover:scale-110 active:scale-95 transition-all animate-in slide-in-from-left-4 duration-300 border border-white/10"
            title="Expandir Menu"
          >
            <PanelLeftOpen size={24} />
          </button>
        )}

        {notification && (
          <div className={`fixed top-4 right-4 md:top-6 md:right-6 z-[200] flex items-center gap-3 px-4 md:px-6 py-3 md:py-4 rounded-xl md:rounded-2xl shadow-2xl border animate-in slide-in-from-top-6 duration-300 w-[calc(100%-2rem)] md:w-auto ${notification.type === 'success' ? 'bg-emerald-50 dark:bg-dracula-green/20 text-emerald-700 dark:text-dracula-green border-emerald-100 dark:border-dracula-green/40' : 'bg-rose-50 dark:bg-dracula-red/20 text-rose-700 dark:text-dracula-red border-rose-100 dark:border-dracula-red/40'}`}>
            {notification.type === 'success' ? <CheckCircle2 size={20} className="shrink-0" /> : <AlertCircle size={20} className="shrink-0" />}
            <p className="font-bold text-sm leading-tight">{notification.message}</p>
          </div>
        )}

        <div className="max-w-6xl mx-auto space-y-6 md:space-y-8">
          <header className="flex flex-col md:flex-row md:items-end justify-between gap-4">
            <div className="space-y-1">
              <h2 className="text-2xl md:text-3xl font-extrabold text-slate-900 dark:text-dracula-fg tracking-tight flex items-center gap-3">
                {currentView === 'form' ? (editingExchange ? 'Editar Troca' : 'Nova Troca') : 
                 currentView === 'inventory' ? 'InventĂĄrio de Ativos' : 'Caixa de Entrada'}
                {!isSidebarVisible && (
                   <span className="hidden lg:inline-flex bg-dracula-purple/10 text-dracula-purple text-[10px] px-2 py-0.5 rounded-full border border-dracula-purple/20 uppercase tracking-widest font-bold">Modo Foco</span>
                )}
              </h2>
              <p className="text-slate-500 dark:text-dracula-comment font-medium text-sm">Modo Offline Seguro: LocalStorage + Excel Sync</p>
            </div>
            {isLoading && (
              <div className="flex items-center gap-2 text-dracula-purple font-bold bg-dracula-purple/10 px-4 py-2 rounded-xl border border-dracula-purple/20 self-start md:self-end">
                <Loader2 className="animate-spin" size={18} />
                <span className="text-xs uppercase tracking-widest">Sincronizando...</span>
              </div>
            )}
          </header>

          <div className="bg-white dark:bg-dracula-darker rounded-2xl md:rounded-[2.5rem] shadow-xl shadow-slate-200/60 dark:shadow-black/40 border border-slate-100 dark:border-dracula-current overflow-hidden min-h-[500px] lg:min-h-[600px] transition-colors duration-200">
            {currentView === 'form' && (
              <AssetForm 
                onSave={handleSaveExchange} 
                editingExchange={editingExchange} 
                onCancel={() => navTo('inventory')} 
                exchanges={exchanges}
              />
            )}
            {currentView === 'inventory' && (
              <InventoryTable 
                exchanges={exchanges} 
                onDelete={handleDelete} 
                onEdit={(ex) => { setEditingExchange(ex); setCurrentView('form'); }} 
                onNotify={showNotification}
                onSignStart={setSigningExchange}
                onBulkImport={handleBulkImport}
                logoPref={logoPref}
              />
            )}
            {currentView === 'inbox' && (
              <MockInbox 
                emails={emails} 
                onUpdateEmails={setEmails} 
                exchanges={exchanges}
                onSignReceiver={handleSignReceiver}
                logoPref={logoPref}
              />
            )}
          </div>
        </div>

        {signingExchange && (
          <SenderSignatureModal 
            exchange={signingExchange}
            onClose={() => setSigningExchange(null)}
            onConfirm={(id, sig) => handleSignSender(id, sig)}
          />
        )}

        <footer className="max-w-6xl mx-auto mt-8 md:mt-12 flex flex-col sm:flex-row justify-between items-center text-slate-400 dark:text-dracula-comment text-[10px] font-bold uppercase tracking-wider px-4 gap-2 mb-8 md:mb-0">
          <p>Â© 2025 AssetFlow Technologies</p>
          <div className="flex gap-4">
            <span>Logo: {logoPref === 'cirion' ? 'Cirion' : 'Nenhum'}</span>
            <span>Tema: {theme === 'light' ? 'Claro' : 'Dracula Dark'}</span>
            <span>Sidebar: {isSidebarVisible ? 'VisĂ­vel' : 'Foco'}</span>
          </div>
        </footer>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useRef } from 'react';
import { AssetExchange, LogoPreference } from '../types';
import { FileDown, Trash2, Search, FileSpreadsheet, Pencil, Mail, Laptop, Smartphone, Cpu, Clock, Lock, FileCheck, Upload } from 'lucide-react';
import { generateAssetPDF } from '../services/pdfService';
import { exportToExcel, importFromExcel } from '../services/excelService';

interface InventoryTableProps {
  exchanges: AssetExchange[];
  onDelete: (id: string) => void;
  onEdit: (exchange: AssetExchange) => void;
  onNotify: (message: string, type: 'success' | 'error') => void;
  onSignStart: (exchange: AssetExchange) => void;
  onBulkImport: (data: AssetExchange[]) => void;
  logoPref: LogoPreference;
}

const InventoryTable: React.FC<InventoryTableProps> = ({ exchanges, onDelete, onEdit, onNotify, onSignStart, onBulkImport, logoPref }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  const filtered = exchanges.filter(e => 
    e.colaborador_nome.toLowerCase().includes(searchTerm.toLowerCase()) || 
    e.entregue_serial.toLowerCase().includes(searchTerm.toLowerCase()) ||
    e.devolvido_serial.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const handleImportClick = () => {
    fileInputRef.current?.click();
  };

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    try {
      const data = await importFromExcel(file);
      if (confirm(`Deseja importar ${data.length} registros? Isso poderĂĄ sobrescrever dados existentes com o mesmo ID.`)) {
        onBulkImport(data);
        onNotify("Base de dados sincronizada com sucesso!", "success");
      }
    } catch (err) {
      onNotify("Erro ao ler arquivo Excel. Verifique o formato.", "error");
    }
    e.target.value = ''; // Reset input
  };

  const getIcon = (type: string) => {
    const t = type.toLowerCase();
    if (t.includes('note')) return <Laptop size={14} />;
    if (t.includes('smart')) return <Smartphone size={14} />;
    return <Cpu size={14} />;
  };

  const handleDeleteClick = (e: React.MouseEvent, id: string) => {
    e.preventDefault();
    e.stopPropagation();
    onDelete(id);
  };

  return (
    <div className="flex flex-col h-full overflow-hidden transition-colors duration-200">
      <div className="p-4 md:p-6 border-b dark:border-dracula-current flex flex-col xl:flex-row xl:items-center justify-between gap-4">
        <div className="relative flex-1 max-w-full xl:max-w-md">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 dark:text-dracula-comment" size={18} />
          <input 
            placeholder="Buscar por nome ou serial..."
            className="w-full pl-10 pr-4 py-2.5 rounded-xl border dark:border-dracula-current bg-slate-50 dark:bg-dracula-bg dark:text-dracula-fg focus:bg-white dark:focus:bg-dracula-darker transition-all text-sm outline-none focus:ring-2 focus:ring-dracula-purple/30"
            value={searchTerm}
            onChange={e => setSearchTerm(e.target.value)}
          />
        </div>

        <div className="flex flex-wrap items-center gap-2">
          <input 
            type="file" 
            ref={fileInputRef} 
            onChange={handleFileChange} 
            accept=".xlsx, .xls" 
            className="hidden" 
          />
          <button 
            type="button"
            onClick={handleImportClick}
            className="flex-1 sm:flex-none flex items-center justify-center gap-2 bg-slate-100 dark:bg-dracula-bg text-slate-600 dark:text-dracula-fg px-4 py-2.5 rounded-xl font-bold border border-slate-200 dark:border-dracula-current transition-all hover:bg-slate-200 dark:hover:bg-dracula-current active:scale-95 text-xs"
          >
            <Upload size={16} /> Importar Base
          </button>
          <button 
            type="button"
            onClick={() => exportToExcel(exchanges)} 
            className="flex-1 sm:flex-none flex items-center justify-center gap-2 bg-emerald-600 dark:bg-dracula-green text-white px-5 py-2.5 rounded-xl font-bold shadow-lg shadow-emerald-100 dark:shadow-black/20 transition-all hover:bg-emerald-700 dark:hover:bg-dracula-green/80 active:scale-95 text-xs"
          >
            <FileSpreadsheet size={16} /> Exportar Excel
          </button>
        </div>
      </div>

      <div className="flex-1 overflow-x-auto custom-scrollbar">
        <table className="w-full text-left min-w-[900px]">
          <thead className="bg-slate-50 dark:bg-dracula-darker sticky top-0 z-10 border-b dark:border-dracula-current">
            <tr>
              <th className="px-6 py-4 text-[10px] font-bold uppercase text-slate-400 dark:text-dracula-comment tracking-wider">Colaborador</th>
              <th className="px-6 py-4 text-[10px] font-bold uppercase text-slate-400 dark:text-dracula-comment tracking-wider">Equip. Entregue</th>
