export default InventoryTable;

import React, { useState, useEffect, useRef } from 'react';
import { AssetExchange, EquipmentCondition } from '../types';
import { EQUIPMENT_TYPES, BRANDS, MODELS_LIST, PROCESSORS_LIST, MODEL_PROCESSOR_MAP, MEMORY_LIST, STORAGE_LIST, AD_USERS } from '../constants';
import { User, Package, History, Send, ScanLine, Lock, MousePointer2, Loader2, CheckSquare, Search, Fingerprint } from 'lucide-react';
import BarcodeScannerModal from './BarcodeScannerModal';

interface AssetFormProps {
  onSave: (exchange: AssetExchange) => Promise<void> | void;
  editingExchange?: AssetExchange | null;
  onCancel?: () => void;
  exchanges?: AssetExchange[];
}

const ACCESSORIES_OPTIONS = ["Mouse", "Mochila", "Teclado", "DockStation", "Headset", "Monitor"];

const AssetForm: React.FC<AssetFormProps> = ({ onSave, editingExchange, onCancel }) => {
  const isReadOnly = editingExchange?.status === 'completed';
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [showADSuggestions, setShowADSuggestions] = useState(false);
  const [adFilter, setAdFilter] = useState('');
  const adRef = useRef<HTMLDivElement>(null);

  const [formData, setFormData] = useState<AssetExchange>({
    id: '',
    status: 'draft',
    timestamp: Date.now(),
    colaborador_nome: '',
    colaborador_email: '',
    data_troca: new Date().toISOString().split('T')[0],
    observacoes: '',
    entregue_tipo: EQUIPMENT_TYPES[0],
    entregue_marca: BRANDS[0],
    entregue_modelo: MODELS_LIST[0],
    entregue_serial: '',
    entregue_processador: PROCESSORS_LIST[0],
    entregue_condicao: EquipmentCondition.NEW,
    entregue_memoria: MEMORY_LIST[2], // Default 16GB
    entregue_armazenamento: STORAGE_LIST[3], // Default 512GB
    entregue_acessorios: [],
    devolvido_tipo: EQUIPMENT_TYPES[0],
    devolvido_marca: BRANDS[0],
    devolvido_modelo: MODELS_LIST[0],
    devolvido_serial: '',
    devolvido_processador: PROCESSORS_LIST[0],
    devolvido_condicao: EquipmentCondition.USED,
    devolvido_memoria: MEMORY_LIST[2], // Default 16GB
    devolvido_armazenamento: STORAGE_LIST[3], // Default 512GB
    devolvido_acessorios: []
  });

  const [scannerConfig, setScannerConfig] = useState<{ isOpen: boolean; target: 'entregue' | 'devolvido' }>({
    isOpen: false,
    target: 'entregue'
  });

  useEffect(() => {
    if (editingExchange) {
      setFormData({ ...editingExchange });
    }
  }, [editingExchange]);

  // Fechar dropdown do AD ao clicar fora
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (adRef.current && !adRef.current.contains(event.target as Node)) {
        setShowADSuggestions(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleBrandChange = (brand: string, target: 'entregue' | 'devolvido') => {
    if (target === 'entregue') {
      setFormData({ ...formData, entregue_marca: brand });
    } else {
      setFormData({ ...formData, devolvido_marca: brand });
    }
  };

  const handleModelChange = (model: string, target: 'entregue' | 'devolvido') => {
    const mappedProcessor = MODEL_PROCESSOR_MAP[model];

    if (target === 'entregue') {
      setFormData(prev => ({ 
        ...prev, 
        entregue_modelo: model,
        entregue_processador: mappedProcessor || prev.entregue_processador 
      }));
    } else {
      setFormData(prev => ({ 
        ...prev, 
        devolvido_modelo: model,
        devolvido_processador: mappedProcessor || prev.devolvido_processador 
      }));
    }
  };

  const handleAccessoryToggle = (acc: string, target: 'entregue' | 'devolvido') => {
    const field = target === 'entregue' ? 'entregue_acessorios' : 'devolvido_acessorios';
    const current = formData[field] as string[];
    const updated = current.includes(acc) ? current.filter(i => i !== acc) : [...current, acc];
    setFormData({ ...formData, [field]: updated });
  };

  const handleNameInput = (value: string) => {
    setFormData({ ...formData, colaborador_nome: value });
    setAdFilter(value);
    setShowADSuggestions(value.length > 1);
  };

  const selectADUser = (user: { nome: string, email: string }) => {
    setFormData({ 
      ...formData, 
      colaborador_nome: user.nome, 
      colaborador_email: user.email 
    });
    setShowADSuggestions(false);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (isSubmitting) return;

    setIsSubmitting(true);
    try {
      const payload = {
        ...formData,
        id: formData.id || Math.random().toString(36).substr(2, 9).toUpperCase(),
        timestamp: formData.timestamp || Date.now()
      };
      await onSave(payload);
    } catch (err) {
      console.error("Erro ao salvar formulĂĄrio:", err);
    } finally {
      setIsSubmitting(false);
    }
  };

  const filteredADUsers = AD_USERS.filter(user => 
    user.nome.toLowerCase().includes(adFilter.toLowerCase()) || 
    user.email.toLowerCase().includes(adFilter.toLowerCase())
  ).sort((a, b) => a.nome.localeCompare(b.nome));

  const SectionHeader = ({ icon: Icon, title, color }: { icon: any, title: string, color: string }) => (
    <div className="flex items-center gap-3 mb-4 md:mb-6 pb-2 border-b border-slate-100 dark:border-dracula-current">
      <div className={`p-2 rounded-lg ${color}`}>
        <Icon size={18} className="text-white" />
      </div>
      <h3 className="text-base md:text-lg font-semibold text-slate-800 dark:text-dracula-fg">{title}</h3>
    </div>
  );

  return (
    <>
      <form onSubmit={handleSubmit} className="p-4 md:p-8 space-y-8 md:space-y-12 transition-colors duration-200">
        {isReadOnly && (
          <div className="bg-amber-50 dark:bg-dracula-orange/10 border border-amber-200 dark:border-dracula-orange/40 p-4 rounded-xl md:rounded-2xl flex items-center gap-4">
            <Lock size={20} className="text-amber-700 dark:text-dracula-orange shrink-0" />
            <p className="text-amber-900 dark:text-dracula-orange text-sm font-bold">Registro Bloqueado por Assinatura</p>
          </div>
        )}

        <section>
          <SectionHeader icon={User} title="Dados do Colaborador" color="bg-dracula-purple" />
          <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 gap-4 md:gap-6">
            <div className="space-y-1.5 relative" ref={adRef}>
              <label className="text-xs font-bold text-slate-500 dark:text-dracula-comment uppercase">Nome Completo</label>
              <div className="relative group">
                <input 
                  disabled={isReadOnly || isSubmitting} required
                  placeholder="Busque pelo nome..."
                  autoComplete="off"
                  className="w-full px-4 py-2.5 rounded-xl border bg-white dark:bg-dracula-bg dark:border-dracula-current dark:text-dracula-fg focus:ring-2 focus:ring-dracula-purple/20 transition-all text-sm outline-none pl-10"
                  value={formData.colaborador_nome}
                  onChange={e => handleNameInput(e.target.value)}
                  onFocus={() => formData.colaborador_nome.length > 1 && setShowADSuggestions(true)}
                />
                <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 dark:text-dracula-comment" />
              </div>

              {showADSuggestions && filteredADUsers.length > 0 && (
                <div className="absolute top-full left-0 w-full z-[70] mt-1 bg-white dark:bg-dracula-current rounded-xl shadow-2xl border border-slate-100 dark:border-dracula-comment overflow-hidden animate-in fade-in slide-in-from-top-2 duration-200">
                  <div className="p-2 bg-slate-50 dark:bg-dracula-darker border-b dark:border-dracula-comment/30 flex justify-between items-center">
                     <span className="text-[9px] font-bold text-slate-400 dark:text-dracula-comment uppercase tracking-widest">
                        DiretĂłrio Office 365
                     </span>
                     <span className="text-[9px] font-bold text-dracula-purple">
                        {filteredADUsers.length} encontrados
                     </span>
                  </div>
                  <div className="max-h-64 overflow-y-auto ad-scrollbar">
                    {filteredADUsers.map((user, idx) => (
                      <button
                        key={idx}
                        type="button"
                        onClick={() => selectADUser(user)}
                        className="w-full px-4 py-3 text-left hover:bg-slate-50 dark:hover:bg-dracula-bg transition-colors flex flex-col gap-0.5 border-b border-slate-50 dark:border-dracula-darker last:border-0"
                      >
                        <span className="font-bold text-sm text-slate-900 dark:text-dracula-fg">{user.nome}</span>
                        <span className="text-[10px] text-slate-500 dark:text-dracula-cyan">{user.email}</span>
                      </button>
                    ))}
                  </div>
                </div>
              )}
            </div>

            <div className="space-y-1.5">
              <label className="text-xs font-bold text-slate-500 dark:text-dracula-comment uppercase">E-mail Corporativo</label>
              <input 
                disabled={isReadOnly || isSubmitting} required type="email"
                placeholder="joao.silva@cirion.com"
                className="w-full px-4 py-2.5 rounded-xl border bg-white dark:bg-dracula-bg dark:border-dracula-current dark:text-dracula-fg focus:ring-2 focus:ring-dracula-purple/20 transition-all text-sm outline-none"
                value={formData.colaborador_email}
                onChange={e => setFormData({ ...formData, colaborador_email: e.target.value })}
              />
            </div>

            <div className="space-y-1.5 sm:col-span-2 md:col-span-1">
              <label className="text-xs font-bold text-slate-500 dark:text-dracula-comment uppercase">Data da Troca</label>
              <input 
                disabled={isReadOnly || isSubmitting} required type="date"
                className="w-full px-4 py-2.5 rounded-xl border bg-white dark:bg-dracula-bg dark:border-dracula-current dark:text-dracula-fg focus:ring-2 focus:ring-dracula-purple/20 transition-all text-sm outline-none"
                value={formData.data_troca}
                onChange={e => setFormData({ ...formData, data_troca: e.target.value })}
              />
            </div>
          </div>
        </section>

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 md:gap-12">
          {/* Entregue */}
          <section className="p-4 md:p-6 rounded-2xl bg-slate-50 dark:bg-dracula-bg/50 border border-slate-100 dark:border-dracula-current">
            <SectionHeader icon={Package} title="Equipamento Entregue" color="bg-dracula-green" />
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              <div className="space-y-1">
                <label className="text-[10px] font-bold text-slate-500 dark:text-dracula-comment uppercase">Tipo</label>
                <select disabled={isReadOnly || isSubmitting} className="w-full px-3 py-2 rounded-lg border bg-white dark:bg-dracula-bg dark:border-dracula-current dark:text-dracula-fg text-sm" value={formData.entregue_tipo} onChange={e => setFormData({...formData, entregue_tipo: e.target.value})}>
                  {EQUIPMENT_TYPES.map(t => <option key={t} value={t}>{t}</option>)}
                </select>
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-bold text-slate-500 dark:text-dracula-comment uppercase">Marca</label>
                <select disabled={isReadOnly || isSubmitting} className="w-full px-3 py-2 rounded-lg border bg-white dark:bg-dracula-bg dark:border-dracula-current dark:text-dracula-fg text-sm" value={formData.entregue_marca} onChange={e => handleBrandChange(e.target.value, 'entregue')}>
