                    value={formData.entregue_serial} 
                    onChange={e => setFormData({...formData, entregue_serial: e.target.value})} 
                  />
                  {!isReadOnly && !isSubmitting && <button type="button" onClick={() => setScannerConfig({isOpen: true, target: 'entregue'})} className="absolute right-2 top-1/2 -translate-y-1/2 text-blue-600 dark:text-dracula-cyan hover:scale-110 transition-transform p-1"><ScanLine size={18}/></button>}
                </div>
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-bold text-slate-500 dark:text-dracula-comment uppercase">Estado</label>
                <select disabled={isReadOnly || isSubmitting} className="w-full px-3 py-2 rounded-lg border bg-white dark:bg-dracula-bg dark:border-dracula-current dark:text-dracula-fg text-sm" value={formData.entregue_condicao} onChange={e => setFormData({...formData, entregue_condicao: e.target.value as EquipmentCondition})}>
