            type="button" 
            onClick={onCancel} 
            disabled={isSubmitting}
            className="px-8 py-3.5 rounded-xl md:rounded-2xl font-bold text-slate-500 dark:text-dracula-comment hover:bg-slate-100 dark:hover:bg-dracula-current transition-colors disabled:opacity-30 text-sm"
