            <button 
              type="submit" 
              disabled={isSubmitting}
              className="flex items-center justify-center gap-2 bg-dracula-purple hover:bg-dracula-purple/80 text-white px-8 md:px-10 py-3.5 rounded-xl md:rounded-2xl font-bold shadow-xl shadow-dracula-purple/20 transition-all active:scale-95 disabled:bg-dracula-purple/50 text-sm"
            >
              {isSubmitting ? (
                <>
                  <Loader2 className="animate-spin" size={18} />
                  <span>Gravando...</span>
                </>
              ) : (
                <>
                  <Send size={18} />
                  <span>{editingExchange ? 'Salvar Registro' : 'Gravar Registro'}</span>
                </>
              )}
            </button>
          )}
        </div>
      </form>

      {scannerConfig.isOpen && (
        <BarcodeScannerModal 
          title={scannerConfig.target === 'entregue' ? 'Lendo Serial Entregue' : 'Lendo Serial Devolvido'}
          onScan={(text) => {
            const processed = text.trim();
            if (scannerConfig.target === 'entregue') setFormData({...formData, entregue_serial: processed});
            else setFormData({...formData, devolvido_serial: processed});
            setScannerConfig({...scannerConfig, isOpen: false});
          }}
          onClose={() => setScannerConfig({...scannerConfig, isOpen: false})}
        />
      )}

      <style>{`
        .ad-scrollbar::-webkit-scrollbar {
          width: 5px;
        }
        .ad-scrollbar::-webkit-scrollbar-track {
          background: transparent;
        }
        .ad-scrollbar::-webkit-scrollbar-thumb {
          background: #44475a;
          border-radius: 10px;
        }
        .ad-scrollbar::-webkit-scrollbar-thumb:hover {
          background: #6272a4;
        }
      `}</style>
    </>
  );
};

export default AssetForm;

import React, { useState, useRef } from 'react';
import { AssetExchange, LogoPreference } from '../types';
import { FileDown, Trash2, Search, FileSpreadsheet, Pencil, Mail, Laptop, Smartphone, Cpu, Clock, Lock, FileCheck, Upload, Fingerprint } from 'lucide-react';
import { generateAssetPDF } from '../services/pdfService';
import { exportToExcel, importFromExcel } from '../services/excelService';

interface InventoryTableProps {
  exchanges: AssetExchange[];
  onDelete: (id: string) => void;
  onEdit: (exchange: AssetExchange) => void;
  onNotify: (message: string, type: 'success' | 'error') => void;
  onSignStart: (exchange: AssetExchange) => void;
  onBulkImport: (data: AssetExchange[]) => void;
  logoPref: LogoPreference;
}

const InventoryTable: React.FC<InventoryTableProps> = ({ exchanges, onDelete, onEdit, onNotify, onSignStart, onBulkImport, logoPref }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  const filtered = exchanges.filter(e => 
    e.colaborador_nome.toLowerCase().includes(searchTerm.toLowerCase()) || 
    e.entregue_serial.toLowerCase().includes(searchTerm.toLowerCase()) ||
    e.devolvido_serial.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const handleImportClick = () => {
    fileInputRef.current?.click();
  };

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    try {
      const data = await importFromExcel(file);
      if (confirm(`Deseja importar ${data.length} registros? Isso poderĂĄ sobrescrever dados existentes com o mesmo ID.`)) {
        onBulkImport(data);
        onNotify("Base de dados sincronizada com sucesso!", "success");
      }
    } catch (err) {
      onNotify("Erro ao ler arquivo Excel. Verifique o formato.", "error");
    }
    e.target.value = ''; // Reset input
  };

  const getIcon = (type: string) => {
    const t = type.toLowerCase();
    if (t.includes('note')) return <Laptop size={14} />;
    if (t.includes('smart')) return <Smartphone size={14} />;
    return <Cpu size={14} />;
  };

  const handleDeleteClick = (e: React.MouseEvent, id: string) => {
    e.preventDefault();
    e.stopPropagation();
    onDelete(id);
  };

  return (
    <div className="flex flex-col h-full overflow-hidden transition-colors duration-200">
      <div className="p-4 md:p-6 border-b dark:border-dracula-current flex flex-col xl:flex-row xl:items-center justify-between gap-4">
        <div className="relative flex-1 max-w-full xl:max-w-md">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 dark:text-dracula-comment" size={18} />
          <input 
            placeholder="Buscar por nome ou serial..."
            className="w-full pl-10 pr-4 py-2.5 rounded-xl border dark:border-dracula-current bg-slate-50 dark:bg-dracula-bg dark:text-dracula-fg focus:bg-white dark:focus:bg-dracula-darker transition-all text-sm outline-none focus:ring-2 focus:ring-dracula-purple/30"
            value={searchTerm}
            onChange={e => setSearchTerm(e.target.value)}
          />
        </div>

        <div className="flex flex-wrap items-center gap-2">
          <input 
            type="file" 
            ref={fileInputRef} 
            onChange={handleFileChange} 
            accept=".xlsx, .xls" 
            className="hidden" 
          />
          <button 
            type="button"
            onClick={handleImportClick}
            className="flex-1 sm:flex-none flex items-center justify-center gap-2 bg-slate-100 dark:bg-dracula-bg text-slate-600 dark:text-dracula-fg px-4 py-2.5 rounded-xl font-bold border border-slate-200 dark:border-dracula-current transition-all hover:bg-slate-200 dark:hover:bg-dracula-current active:scale-95 text-xs"
          >
            <Upload size={16} /> Importar Base
          </button>
          <button 
            type="button"
            onClick={() => exportToExcel(exchanges)} 
            className="flex-1 sm:flex-none flex items-center justify-center gap-2 bg-emerald-600 dark:bg-dracula-green text-white px-5 py-2.5 rounded-xl font-bold shadow-lg shadow-emerald-100 dark:shadow-black/20 transition-all hover:bg-emerald-700 dark:hover:bg-dracula-green/80 active:scale-95 text-xs"
          >
            <FileSpreadsheet size={16} /> Exportar Excel
          </button>
        </div>
      </div>

      <div className="flex-1 overflow-x-auto custom-scrollbar">
        <table className="w-full text-left min-w-[900px]">
          <thead className="bg-slate-50 dark:bg-dracula-darker sticky top-0 z-10 border-b dark:border-dracula-current">
            <tr>
              <th className="px-6 py-4 text-[10px] font-bold uppercase text-slate-400 dark:text-dracula-comment tracking-wider">Colaborador</th>
              <th className="px-6 py-4 text-[10px] font-bold uppercase text-slate-400 dark:text-dracula-comment tracking-wider">Equip. Entregue</th>
              <th className="px-6 py-4 text-[10px] font-bold uppercase text-slate-400 dark:text-dracula-comment tracking-wider">Equip. Devolvido</th>
              <th className="px-6 py-4 text-[10px] font-bold uppercase text-slate-400 dark:text-dracula-comment text-center tracking-wider">Status</th>
              <th className="px-6 py-4 text-[10px] font-bold uppercase text-slate-400 dark:text-dracula-comment text-right tracking-wider">AĂ§Ă”es</th>
            </tr>
          </thead>
          <tbody className="divide-y dark:divide-dracula-current">
            {filtered.length === 0 ? (
              <tr>
                <td colSpan={5} className="px-6 py-20 text-center text-slate-400 dark:text-dracula-comment italic bg-white dark:bg-dracula-bg">
                  <div className="flex flex-col items-center gap-2">
                    <Search size={32} className="opacity-10 dark:opacity-5" />
                    <p>Nenhum registro encontrado.</p>
                  </div>
                </td>
              </tr>
            ) : (
              filtered.map(ex => (
                <tr key={ex.id} className="hover:bg-slate-50/80 dark:hover:bg-dracula-current group transition-colors">
                  <td className="px-6 py-4">
                    <div className="flex flex-col">
                      <span className="font-bold text-slate-900 dark:text-dracula-fg text-sm">{ex.colaborador_nome}</span>
                      <span className="text-[10px] text-slate-400 dark:text-dracula-comment font-medium">{ex.colaborador_email}</span>
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex flex-col items-start">
                      <span className="text-[10px] font-bold text-emerald-600 dark:text-dracula-green uppercase flex items-center gap-1 mb-0.5">
                        {getIcon(ex.entregue_tipo)} {ex.entregue_tipo}
                      </span>
                      <span className="text-xs font-semibold text-slate-700 dark:text-dracula-fg">{ex.entregue_marca} {ex.entregue_modelo}</span>
                      <div className="mt-1 flex items-center gap-1.5 px-2 py-0.5 bg-blue-50 dark:bg-dracula-cyan/10 border border-blue-100 dark:border-dracula-cyan/20 rounded md:rounded-md">
                         <Fingerprint size={10} className="text-blue-500 dark:text-dracula-cyan" />
                         <span className="text-[10px] font-mono font-bold text-blue-700 dark:text-dracula-cyan tracking-tighter">S/N: {ex.entregue_serial}</span>
                      </div>
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex flex-col items-start">
                      <span className="text-[10px] font-bold text-rose-600 dark:text-dracula-red uppercase flex items-center gap-1 mb-0.5">
                        {getIcon(ex.devolvido_tipo)} {ex.devolvido_tipo}
                      </span>
                      <span className="text-xs font-semibold text-slate-700 dark:text-dracula-fg">{ex.devolvido_marca} {ex.devolvido_modelo}</span>
                      <div className="mt-1 flex items-center gap-1.5 px-2 py-0.5 bg-rose-50 dark:bg-dracula-red/10 border border-rose-100 dark:border-dracula-red/20 rounded md:rounded-md">
                         <Fingerprint size={10} className="text-rose-500 dark:text-dracula-red" />
                         <span className="text-[10px] font-mono font-bold text-rose-700 dark:text-dracula-red tracking-tighter">S/N: {ex.devolvido_serial}</span>
                      </div>
                    </div>
                  </td>
                  <td className="px-6 py-4 text-center">
                    {ex.status === 'completed' ? (
