                    ) : ex.status === 'pending_receiver' ? (
                      <span className="inline-flex items-center gap-2 bg-blue-50 dark:bg-dracula-cyan/10 text-blue-700 dark:text-dracula-cyan px-3 py-1.5 rounded-full text-[10px] font-bold uppercase tracking-wider border border-blue-100 dark:border-dracula-cyan/40 whitespace-nowrap">
                        <Clock size={14} />
                        AGUARDANDO ASSINATURA
                      </span>
                    ) : (
                      <span className="inline-flex items-center gap-2 bg-slate-100 dark:bg-dracula-bg text-slate-600 dark:text-dracula-comment px-3 py-1.5 rounded-full text-[10px] font-bold uppercase tracking-wider border border-slate-200 dark:border-dracula-current whitespace-nowrap">
                        <Pencil size={14} />
                        RASCUNHO
                      </span>
                    )}
                  </td>
                  <td className="px-6 py-4 text-right">
                    <div className="flex justify-end gap-1 opacity-40 lg:opacity-0 group-hover:opacity-100 transition-opacity">
                      {ex.status === 'draft' && (
                        <button type="button" onClick={() => onSignStart(ex)} title="Enviar para assinatura" className="p-2 text-blue-600 dark:text-dracula-purple hover:bg-blue-50 dark:hover:bg-dracula-current rounded-xl transition-colors"><Mail size={16}/></button>
                      )}
                      {ex.status !== 'completed' ? (
                        <button type="button" onClick={() => onEdit(ex)} title="Editar registro" className="p-2 text-indigo-600 dark:text-dracula-orange hover:bg-indigo-50 dark:hover:bg-dracula-current rounded-xl transition-colors"><Pencil size={16}/></button>
                      ) : (
                        <div className="p-2 text-slate-300 dark:text-dracula-comment" title="Registro Finalizado"><Lock size={16}/></div>
