        </div>

        {signingExchange && (
          <SenderSignatureModal 
            exchange={signingExchange}
            onClose={() => setSigningExchange(null)}
            onConfirm={(id, sig) => handleSignSender(id, sig)}
          />
        )}

        {showConfigModal && (
          <div className="fixed inset-0 z-[200] flex items-center justify-center p-4 bg-slate-900/80 backdrop-blur-md animate-in fade-in">
             <div className="bg-white dark:bg-dracula-bg w-full max-w-md rounded-3xl p-8 border dark:border-dracula-current shadow-2xl">
                <div className="flex items-center gap-3 mb-6">
                   <div className="p-2 bg-dracula-purple text-white rounded-lg">
                      <Settings size={20} />
                   </div>
                   <h3 className="text-xl font-bold text-slate-800 dark:text-dracula-fg">Configurar M365</h3>
                </div>
                <p className="text-sm text-slate-500 dark:text-dracula-comment mb-6">Insira os IDs da sua aplicaĂ§ĂŁo registrada no Portal Azure (Entra ID) para habilitar a busca corporativa.</p>
                <div className="space-y-4">
                   <div className="space-y-1">
                      <label className="text-[10px] font-bold text-slate-400 uppercase ml-1">Application (Client) ID</label>
                      <input 
                        id="m365_client_id"
                        placeholder="00000000-0000-0000-0000-000000000000"
                        className="w-full px-4 py-3 rounded-xl border dark:border-dracula-current bg-slate-50 dark:bg-dracula-darker dark:text-dracula-fg outline-none focus:ring-2 focus:ring-dracula-purple/30 transition-all font-mono text-xs"
                      />
                   </div>
                   <div className="space-y-1">
                      <label className="text-[10px] font-bold text-slate-400 uppercase ml-1">Directory (Tenant) ID</label>
                      <input 
                        id="m365_tenant_id"
