                          const tid = (document.getElementById('m365_tenant_id') as HTMLInputElement).value;
                          if (cid && tid) {
                            m365Service.updateConfig(cid, tid);
                            setShowConfigModal(false);
                            showNotification("ConfiguraĂ§Ă”es salvas. Tente conectar novamente.");
