  const navTo = (view: View) => {
    setEditingExchange(null);
    setSigningExchange(null);
    setCurrentView(view);
    setIsMobileMenuOpen(false);
  };

  return (
    <div className="flex flex-col lg:flex-row min-h-screen bg-slate-50 dark:bg-dracula-bg text-slate-900 dark:text-dracula-fg font-sans overflow-x-hidden">

      {/* Universal Header (Mobile & Tablet Focus) */}
