          <div className="flex items-center gap-2">
            <div className="w-8 h-8 bg-dracula-purple rounded-lg flex items-center justify-center">
              <HardDrive className="text-white" size={16} />
            </div>
            <h1 className="text-lg font-bold tracking-tight">AssetFlow</h1>
          </div>
        </div>
        <div className="flex items-center gap-2">
          <button 
