        </div>

        {/* Mobile Header in Sidebar */}
        <div className="lg:hidden p-6 flex items-center justify-between border-b border-slate-800">
           <div className="flex items-center gap-2">
              <HardDrive className="text-dracula-purple" size={24} />
              <span className="font-bold text-xl">Menu</span>
           </div>
           <button onClick={() => setIsMobileMenuOpen(false)} className="p-2 bg-slate-800 rounded-full"><X size={20}/></button>
        </div>

        <nav className="flex-1 px-4 py-6 space-y-1.5 overflow-y-auto">
          <NavItem icon={PlusCircle} label="Nova Troca" active={currentView === 'form'} onClick={() => navTo('form')} />
          <NavItem icon={ClipboardList} label="InventĂĄrio" active={currentView === 'inventory'} onClick={() => navTo('inventory')} />
          <NavItem icon={Mail} label="Outlook" active={currentView === 'inbox'} onClick={() => navTo('inbox')} badge={emails.some(e => !e.read)} />

          <div className="pt-8 px-4">
             <div className="text-[10px] text-slate-500 uppercase font-bold tracking-widest mb-4">M365 Cloud</div>
             <button
                onClick={m365Account ? handleM365Logout : handleM365Login}
                className={`w-full flex items-center gap-3 p-3 rounded-xl transition-all ${m365Account ? 'bg-emerald-500/10 text-emerald-400 border border-emerald-500/20' : 'bg-white/5 text-slate-400 hover:bg-white/10'}`}
              >
                <ShieldCheck size={18} className={m365Account ? 'text-emerald-500' : 'text-slate-600'} />
                <div className="text-left overflow-hidden">
                  <div className="text-xs font-bold truncate">{m365Account ? 'Conectado' : 'Entrar'}</div>
