           </button>
           <button className="flex items-center gap-3 text-xs font-bold text-slate-500 hover:text-rose-400 transition-colors">
              <LogOut size={16} /> Encerrar
           </button>
        </div>
      </aside>

      {/* Content Area */}
      <main className={`flex-1 overflow-x-hidden overflow-y-auto transition-all duration-300 relative ${!isSidebarVisible && 'lg:pl-0'}`}>

        {/* Toggle Sidebar Button (Floating Desktop) */}
        {!isSidebarVisible && (
          <button 
            onClick={() => setIsSidebarVisible(true)}
            className="hidden lg:flex fixed left-6 top-8 z-50 p-2.5 bg-slate-900 text-white rounded-xl shadow-2xl hover:scale-105 transition-all border border-white/10"
          >
            <PanelLeftOpen size={24} />
          </button>
        )}

        {notification && (
          <div className="fixed top-20 right-4 lg:top-6 lg:right-6 z-[100] animate-in slide-in-from-right duration-300">
            <div className={`px-6 py-4 rounded-2xl shadow-2xl border flex items-center gap-3 ${notification.type === 'success' ? 'bg-emerald-50 border-emerald-200 text-emerald-800 dark:bg-dracula-green/20 dark:text-dracula-green' : 'bg-rose-50 border-rose-200 text-rose-800 dark:bg-dracula-red/20 dark:text-dracula-red'}`}>
              {notification.type === 'success' ? <CheckCircle2 size={20} /> : <AlertCircle size={20} />}
              <span className="font-bold text-sm">{notification.message}</span>
            </div>
          </div>
        )}

        <div className="max-w-6xl mx-auto p-4 md:p-10 space-y-8">
          <header className="space-y-2">
            <h2 className="text-2xl md:text-3xl font-extrabold tracking-tight">
              {currentView === 'form' ? (editingExchange ? 'Editar Registro' : 'InĂ­cio') : 
               currentView === 'inventory' ? 'Ativos' : 'Inbox'}
            </h2>
            <div className="flex items-center gap-2 text-slate-500 text-xs font-medium">
              <span className="bg-slate-200 dark:bg-dracula-current px-2 py-0.5 rounded uppercase tracking-tighter">v2.4.0</span>
              <span>SincronizaĂ§ĂŁo Ativa</span>
            </div>
          </header>

          <div className="bg-white dark:bg-dracula-darker rounded-[2rem] shadow-2xl shadow-slate-200/50 dark:shadow-black/20 border border-slate-100 dark:border-dracula-current min-h-[500px] overflow-hidden">
            {currentView === 'form' && (
              <AssetForm 
                onSave={handleSaveExchange} 
                editingExchange={editingExchange} 
                onCancel={() => navTo('inventory')} 
                m365Connected={!!m365Account}
              />
            )}
            {currentView === 'inventory' && (
              <InventoryTable 
                exchanges={exchanges} 
                onDelete={handleDelete} 
                onEdit={(ex) => { setEditingExchange(ex); setCurrentView('form'); }} 
                onNotify={showNotification}
                onSignStart={setSigningExchange}
                onBulkImport={handleBulkImport}
                logoPref={logoPref}
              />
            )}
            {currentView === 'inbox' && (
              <MockInbox 
                emails={emails} 
                onUpdateEmails={setEmails} 
                exchanges={exchanges}
                onSignReceiver={handleSignReceiver}
                logoPref={logoPref}
              />
            )}
          </div>
        </div>

        {signingExchange && <SenderSignatureModal exchange={signingExchange} onClose={() => setSigningExchange(null)} onConfirm={handleSignSender} />}
        {showConfigModal && <M365ConfigModal onClose={() => setShowConfigModal(false)} onNotify={showNotification} />}

        <footer className="p-10 text-center text-[10px] font-bold text-slate-400 uppercase tracking-[0.2em]">
           Â© 2025 AssetFlow âą Desenvolvido para Cirion TI
        </footer>
      </main>
    </div>
  );
};

// Subcomponente de Item de NavegaĂ§ĂŁo para reuso
const NavItem = ({ icon: Icon, label, active, onClick, badge }: any) => (
  <button
    onClick={onClick}
    className={`w-full flex items-center gap-4 px-4 py-3.5 rounded-xl transition-all relative ${active ? 'bg-dracula-purple text-white shadow-lg' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}
  >
    <Icon size={20} />
