);

const M365ConfigModal = ({ onClose, onNotify }: any) => {
  const save = () => {
    const cid = (document.getElementById('cid') as HTMLInputElement).value;
    const tid = (document.getElementById('tid') as HTMLInputElement).value;
    if (cid && tid) {
      m365Service.updateConfig(cid, tid);
      onNotify("ConfiguraĂ§ĂŁo do Azure salva!");
      onClose();
    }
  };

  return (
    <div className="fixed inset-0 z-[200] flex items-center justify-center p-4 bg-slate-900/90 backdrop-blur-md animate-in fade-in">
      <div className="bg-white dark:bg-dracula-bg w-full max-w-sm rounded-[2rem] p-8 border dark:border-dracula-current shadow-2xl">
        <h3 className="text-xl font-bold mb-6 flex items-center gap-2"><Settings className="text-dracula-purple"/> Microsoft Tenant</h3>
        <div className="space-y-4">
          <input id="cid" placeholder="Client ID" className="w-full p-4 rounded-xl border dark:bg-dracula-darker text-xs font-mono outline-none focus:ring-2 ring-dracula-purple/50"/>
          <input id="tid" placeholder="Tenant ID (ex: common)" className="w-full p-4 rounded-xl border dark:bg-dracula-darker text-xs font-mono outline-none focus:ring-2 ring-dracula-purple/50"/>
          <div className="flex gap-3 pt-4">
            <button onClick={onClose} className="flex-1 py-3 text-slate-400 font-bold">Cancelar</button>
            <button onClick={save} className="flex-1 py-3 bg-dracula-purple text-white rounded-xl font-bold">Salvar</button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { AssetExchange, EquipmentCondition } from '../types';
import { EQUIPMENT_TYPES, BRANDS, MODELS_LIST, PROCESSORS_LIST, MODEL_PROCESSOR_MAP, MEMORY_LIST, STORAGE_LIST, AD_USERS } from '../constants';
import { User, Package, History, Send, ScanLine, Lock, MousePointer2, Loader2, CheckSquare, Search, Fingerprint } from 'lucide-react';
import BarcodeScannerModal from './BarcodeScannerModal';
import { m365Service } from '../services/m365Service';

interface AssetFormProps {
  onSave: (exchange: AssetExchange) => Promise<void> | void;
  editingExchange?: AssetExchange | null;
  onCancel?: () => void;
  m365Connected?: boolean;
}

const ACCESSORIES_OPTIONS = ["Mouse", "Mochila", "Teclado", "DockStation", "Headset", "Monitor"];

const AssetForm: React.FC<AssetFormProps> = ({ onSave, editingExchange, onCancel, m365Connected }) => {
  const isReadOnly = editingExchange?.status === 'completed';
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [showSuggestions, setShowSuggestions] = useState(false);
  const [suggestedUsers, setSuggestedUsers] = useState<any[]>([]);
  const [isSearching, setIsSearching] = useState(false);
  const adRef = useRef<HTMLDivElement>(null);
  const searchTimeoutRef = useRef<number | null>(null);

  const [formData, setFormData] = useState<AssetExchange>({
    id: '',
    status: 'draft',
    timestamp: Date.now(),
    colaborador_nome: '',
    colaborador_email: '',
    data_troca: new Date().toISOString().split('T')[0],
    observacoes: '',
    entregue_tipo: EQUIPMENT_TYPES[0],
    entregue_marca: BRANDS[0],
    entregue_modelo: MODELS_LIST[0],
    entregue_serial: '',
    entregue_processador: PROCESSORS_LIST[0],
    entregue_condicao: EquipmentCondition.NEW,
    entregue_memoria: MEMORY_LIST[2],
    entregue_armazenamento: STORAGE_LIST[3],
    entregue_acessorios: [],
    devolvido_tipo: EQUIPMENT_TYPES[0],
    devolvido_marca: BRANDS[0],
    devolvido_modelo: MODELS_LIST[0],
    devolvido_serial: '',
    devolvido_processador: PROCESSORS_LIST[0],
    devolvido_condicao: EquipmentCondition.USED,
    devolvido_memoria: MEMORY_LIST[2],
    devolvido_armazenamento: STORAGE_LIST[3],
    devolvido_acessorios: []
  });

  const [scannerConfig, setScannerConfig] = useState<{ isOpen: boolean; target: 'entregue' | 'devolvido' }>({
    isOpen: false,
    target: 'entregue'
  });

  useEffect(() => {
    if (editingExchange) setFormData({ ...editingExchange });
  }, [editingExchange]);

  useEffect(() => {
    const handleClickOutside = (e: MouseEvent) => {
      if (adRef.current && !adRef.current.contains(e.target as Node)) setShowSuggestions(false);
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleNameInput = (value: string) => {
    setFormData({ ...formData, colaborador_nome: value });
    if (value.length < 2) {
      setShowSuggestions(false);
      return;
    }
    setShowSuggestions(true);
    if (searchTimeoutRef.current) clearTimeout(searchTimeoutRef.current);
    searchTimeoutRef.current = window.setTimeout(async () => {
      setIsSearching(true);
      try {
        const results = m365Connected ? await m365Service.searchUsers(value) : 
          AD_USERS.filter(u => u.nome.toLowerCase().includes(value.toLowerCase())).slice(0, 5);
        setSuggestedUsers(results);
      } finally {
        setIsSearching(false);
      }
    }, 400);
  };

  const handleModelChange = (model: string, target: 'entregue' | 'devolvido') => {
    const proc = MODEL_PROCESSOR_MAP[model];
    const prefix = target === 'entregue' ? 'entregue_' : 'devolvido_';
    setFormData(prev => ({ 
      ...prev, 
      [`${prefix}modelo`]: model,
      [`${prefix}processador`]: proc || prev[`${prefix}processador` as keyof AssetExchange]
    }));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (isSubmitting) return;
    setIsSubmitting(true);
    try {
      const payload = { ...formData, id: formData.id || Math.random().toString(36).substr(2, 9).toUpperCase() };
      await onSave(payload);
    } finally {
      setIsSubmitting(false);
    }
  };

  const SectionHeader = ({ icon: Icon, title, color }: any) => (
    <div className="flex items-center gap-3 mb-6 pb-2 border-b border-slate-100 dark:border-dracula-current">
      <div className={`p-2 rounded-lg ${color} shadow-sm`}><Icon size={18} className="text-white" /></div>
      <h3 className="text-lg font-bold">{title}</h3>
    </div>
  );

  return (
    <form onSubmit={handleSubmit} className="p-5 md:p-10 space-y-10">
      {isReadOnly && (
        <div className="bg-amber-50 dark:bg-dracula-orange/10 border border-amber-200 p-4 rounded-2xl flex items-center gap-3">
          <Lock className="text-amber-600" size={20} />
          <span className="text-xs font-bold text-amber-800">DOCUMENTO BLOQUEADO</span>
        </div>
      )}

      {/* Dados Colaborador */}
      <section>
        <SectionHeader icon={User} title="Colaborador" color="bg-dracula-purple" />
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          <div className="relative" ref={adRef}>
            <label className="text-[10px] font-bold text-slate-400 uppercase ml-1">Nome Completo</label>
            <div className="relative mt-1">
              <input disabled={isReadOnly} required className="w-full p-4 rounded-xl border dark:bg-dracula-bg outline-none focus:ring-2 ring-dracula-purple/30 transition-all text-sm pl-10" value={formData.colaborador_nome} onChange={e => handleNameInput(e.target.value)} onFocus={() => setShowSuggestions(true)}/>
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-300" size={16}/>
              {isSearching && <Loader2 className="absolute right-3 top-1/2 -translate-y-1/2 animate-spin text-dracula-purple" size={16}/>}
            </div>
            {showSuggestions && suggestedUsers.length > 0 && (
              <div className="absolute top-full left-0 w-full z-[100] mt-1 bg-white dark:bg-dracula-current rounded-xl shadow-2xl border overflow-hidden">
                {suggestedUsers.map((u, i) => (
                  <button key={i} type="button" onClick={() => { setFormData({...formData, colaborador_nome: u.nome, colaborador_email: u.email}); setShowSuggestions(false); }} className="w-full p-3 text-left hover:bg-slate-50 dark:hover:bg-dracula-bg border-b last:border-0">
                    <div className="font-bold text-xs">{u.nome}</div>
                    <div className="text-[10px] text-slate-400">{u.email}</div>
                  </button>
                ))}
              </div>
            )}
          </div>
          <div>
            <label className="text-[10px] font-bold text-slate-400 uppercase ml-1">E-mail</label>
            <input disabled={isReadOnly} type="email" required className="w-full p-4 rounded-xl border mt-1 dark:bg-dracula-bg text-sm" value={formData.colaborador_email} onChange={e => setFormData({...formData, colaborador_email: e.target.value})}/>
          </div>
          <div>
            <label className="text-[10px] font-bold text-slate-400 uppercase ml-1">Data</label>
            <input disabled={isReadOnly} type="date" required className="w-full p-4 rounded-xl border mt-1 dark:bg-dracula-bg text-sm" value={formData.data_troca} onChange={e => setFormData({...formData, data_troca: e.target.value})}/>
          </div>
        </div>
      </section>

      {/* Equipamentos - Grid Responsivo Tablet/Desktop */}
      <div className="grid grid-cols-1 xl:grid-cols-2 gap-10">
        {/* Entregue */}
        <div className="p-6 bg-slate-50 dark:bg-dracula-bg/40 rounded-3xl border border-slate-100 dark:border-dracula-current">
          <SectionHeader icon={Package} title="Entregue" color="bg-dracula-green" />
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            <div className="sm:col-span-2 relative">
               <label className="text-[10px] font-bold text-blue-500 uppercase flex items-center gap-1"><Fingerprint size={12}/> Serial / IMEI</label>
               <input disabled={isReadOnly} required className="w-full p-3 rounded-xl border-2 border-blue-400 dark:border-dracula-cyan bg-blue-50/30 dark:bg-dracula-cyan/5 font-mono font-bold mt-1 text-sm pr-12" value={formData.entregue_serial} onChange={e => setFormData({...formData, entregue_serial: e.target.value})}/>
               {!isReadOnly && <button type="button" onClick={() => setScannerConfig({isOpen: true, target: 'entregue'})} className="absolute right-3 top-9 text-blue-600"><ScanLine size={20}/></button>}
            </div>
            <div>
              <label className="text-[10px] font-bold text-slate-400 uppercase">Modelo</label>
              <select className="w-full p-3 rounded-xl border mt-1 bg-white dark:bg-dracula-bg text-xs" value={formData.entregue_modelo} onChange={e => handleModelChange(e.target.value, 'entregue')}>
                {MODELS_LIST.map(m => <option key={m} value={m}>{m}</option>)}
              </select>
            </div>
            <div>
              <label className="text-[10px] font-bold text-slate-400 uppercase">Estado</label>
              <select className="w-full p-3 rounded-xl border mt-1 bg-white dark:bg-dracula-bg text-xs" value={formData.entregue_condicao} onChange={e => setFormData({...formData, entregue_condicao: e.target.value as EquipmentCondition})}>
                <option value={EquipmentCondition.NEW}>Novo</option>
                <option value={EquipmentCondition.USED}>Usado</option>
              </select>
            </div>
          </div>
        </div>

        {/* Devolvido */}
        <div className="p-6 bg-slate-50 dark:bg-dracula-bg/40 rounded-3xl border border-slate-100 dark:border-dracula-current">
          <SectionHeader icon={History} title="Devolvido" color="bg-dracula-red" />
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            <div className="sm:col-span-2 relative">
               <label className="text-[10px] font-bold text-rose-500 uppercase flex items-center gap-1"><Fingerprint size={12}/> Serial / IMEI</label>
               <input disabled={isReadOnly} required className="w-full p-3 rounded-xl border-2 border-rose-400 dark:border-dracula-red bg-rose-50/30 dark:bg-dracula-red/5 font-mono font-bold mt-1 text-sm pr-12" value={formData.devolvido_serial} onChange={e => setFormData({...formData, devolvido_serial: e.target.value})}/>
               {!isReadOnly && <button type="button" onClick={() => setScannerConfig({isOpen: true, target: 'devolvido'})} className="absolute right-3 top-9 text-rose-600"><ScanLine size={20}/></button>}
            </div>
            <div>
              <label className="text-[10px] font-bold text-slate-400 uppercase">Modelo</label>
              <select className="w-full p-3 rounded-xl border mt-1 bg-white dark:bg-dracula-bg text-xs" value={formData.devolvido_modelo} onChange={e => handleModelChange(e.target.value, 'devolvido')}>
                {MODELS_LIST.map(m => <option key={m} value={m}>{m}</option>)}
              </select>
            </div>
            <div>
              <label className="text-[10px] font-bold text-slate-400 uppercase">Estado</label>
              <select className="w-full p-3 rounded-xl border mt-1 bg-white dark:bg-dracula-bg text-xs" value={formData.devolvido_condicao} onChange={e => setFormData({...formData, devolvido_condicao: e.target.value as EquipmentCondition})}>
                <option value={EquipmentCondition.NEW}>Novo</option>
                <option value={EquipmentCondition.USED}>Usado</option>
              </select>
            </div>
          </div>
        </div>
      </div>

      <section>
        <SectionHeader icon={MousePointer2} title="Notas" color="bg-slate-400" />
        <textarea disabled={isReadOnly} className="w-full p-4 rounded-2xl border dark:bg-dracula-bg h-24 text-sm" value={formData.observacoes} onChange={e => setFormData({...formData, observacoes: e.target.value})} placeholder="InformaĂ§Ă”es adicionais..."/>
      </section>

      <div className="flex flex-col sm:flex-row justify-end gap-4 pt-4">
        <button type="button" onClick={onCancel} className="px-8 py-4 font-bold text-slate-400 hover:text-slate-600">Cancelar</button>
        {!isReadOnly && (
          <button type="submit" disabled={isSubmitting} className="px-10 py-4 bg-dracula-purple text-white rounded-2xl font-bold shadow-xl flex items-center justify-center gap-2">
            {isSubmitting ? <Loader2 className="animate-spin" size={20}/> : <Send size={20}/>}
            {editingExchange ? 'Salvar' : 'Gravar'}
          </button>
        )}
      </div>

      {scannerConfig.isOpen && (
        <BarcodeScannerModal 
          title={scannerConfig.target === 'entregue' ? 'Serial Entregue' : 'Serial Devolvido'}
          onScan={(text) => {
            const prefix = scannerConfig.target === 'entregue' ? 'entregue_' : 'devolvido_';
            setFormData({...formData, [`${prefix}serial`]: text});
            setScannerConfig({...scannerConfig, isOpen: false});
          }}
          onClose={() => setScannerConfig({...scannerConfig, isOpen: false})}
        />
      )}
    </form>
  );
};

