);

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { AssetExchange, EquipmentCondition } from '../types';
import { EQUIPMENT_TYPES, BRANDS, MODELS_LIST, PROCESSORS_LIST, MODEL_PROCESSOR_MAP, MEMORY_LIST, STORAGE_LIST, AD_USERS } from '../constants';
import { User, Package, History, Send, ScanLine, Lock, MousePointer2, Loader2, Search, Fingerprint, CheckSquare } from 'lucide-react';
import BarcodeScannerModal from './BarcodeScannerModal';
import { m365Service } from '../services/m365Service';

interface AssetFormProps {
  onSave: (exchange: AssetExchange) => Promise<void> | void;
  editingExchange?: AssetExchange | null;
  onCancel?: () => void;
  m365Connected?: boolean;
}

const ACCESSORIES_OPTIONS = ["Mouse", "Mochila", "Teclado", "DockStation", "Headset", "Monitor"];

const AssetForm: React.FC<AssetFormProps> = ({ onSave, editingExchange, onCancel, m365Connected }) => {
  const isReadOnly = editingExchange?.status === 'completed';
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [showSuggestions, setShowSuggestions] = useState(false);
  const [suggestedUsers, setSuggestedUsers] = useState<any[]>([]);
  const [isSearching, setIsSearching] = useState(false);
  const adRef = useRef<HTMLDivElement>(null);
  const searchTimeoutRef = useRef<number | null>(null);

  const [formData, setFormData] = useState<AssetExchange>({
    id: '',
    status: 'draft',
    timestamp: Date.now(),
    colaborador_nome: '',
    colaborador_email: '',
    data_troca: new Date().toISOString().split('T')[0],
    observacoes: '',
    entregue_tipo: EQUIPMENT_TYPES[0],
    entregue_marca: BRANDS[0],
    entregue_modelo: MODELS_LIST[0],
    entregue_serial: '',
    entregue_processador: PROCESSORS_LIST[0],
    entregue_condicao: EquipmentCondition.NEW,
    entregue_memoria: MEMORY_LIST[2],
    entregue_armazenamento: STORAGE_LIST[3],
    entregue_acessorios: [],
    devolvido_tipo: EQUIPMENT_TYPES[0],
    devolvido_marca: BRANDS[0],
    devolvido_modelo: MODELS_LIST[0],
    devolvido_serial: '',
    devolvido_processador: PROCESSORS_LIST[0],
    devolvido_condicao: EquipmentCondition.USED,
    devolvido_memoria: MEMORY_LIST[2],
    devolvido_armazenamento: STORAGE_LIST[3],
    devolvido_acessorios: []
  });

  const [scannerConfig, setScannerConfig] = useState<{ isOpen: boolean; target: 'entregue' | 'devolvido' }>({
    isOpen: false,
    target: 'entregue'
  });

  useEffect(() => {
    if (editingExchange) setFormData({ ...editingExchange });
  }, [editingExchange]);

  useEffect(() => {
    const handleClickOutside = (e: MouseEvent) => {
      if (adRef.current && !adRef.current.contains(e.target as Node)) setShowSuggestions(false);
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleNameInput = (value: string) => {
    setFormData({ ...formData, colaborador_nome: value });
    if (value.length < 2) {
      setShowSuggestions(false);
      return;
    }
    setShowSuggestions(true);
    if (searchTimeoutRef.current) clearTimeout(searchTimeoutRef.current);
    searchTimeoutRef.current = window.setTimeout(async () => {
      setIsSearching(true);
      try {
        const results = m365Connected ? await m365Service.searchUsers(value) : 
          AD_USERS.filter(u => u.nome.toLowerCase().includes(value.toLowerCase())).slice(0, 5);
        setSuggestedUsers(results);
      } finally {
        setIsSearching(false);
      }
    }, 400);
  };

  const handleModelChange = (model: string, target: 'entregue' | 'devolvido') => {
    const proc = MODEL_PROCESSOR_MAP[model];
    const prefix = target === 'entregue' ? 'entregue_' : 'devolvido_';
    setFormData(prev => ({ 
      ...prev, 
      [`${prefix}modelo`]: model,
      [`${prefix}processador`]: proc || prev[`${prefix}processador` as keyof AssetExchange]
    }));
  };

  const handleAccessoryToggle = (acc: string, target: 'entregue' | 'devolvido') => {
    const prefix = target === 'entregue' ? 'entregue_acessorios' : 'devolvido_acessorios';
    const current = formData[prefix] as string[];
    const updated = current.includes(acc) ? current.filter(a => a !== acc) : [...current, acc];
    setFormData({ ...formData, [prefix]: updated });
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (isSubmitting) return;
    setIsSubmitting(true);
    try {
      const payload = { ...formData, id: formData.id || Math.random().toString(36).substr(2, 9).toUpperCase() };
      await onSave(payload);
    } finally {
      setIsSubmitting(false);
    }
  };

  const SectionHeader = ({ icon: Icon, title, color }: any) => (
    <div className="flex items-center gap-3 mb-6 pb-2 border-b border-slate-100 dark:border-dracula-current">
      <div className={`p-2 rounded-lg ${color} shadow-sm`}><Icon size={18} className="text-white" /></div>
      <h3 className="text-lg font-bold">{title}</h3>
    </div>
  );

  const EquipmentSection = ({ target }: { target: 'entregue' | 'devolvido' }) => {
    const prefix = target === 'entregue' ? 'entregue_' : 'devolvido_';
    const isEntregue = target === 'entregue';

    return (
      <div className="p-6 bg-slate-50 dark:bg-dracula-bg/40 rounded-3xl border border-slate-100 dark:border-dracula-current space-y-6">
        <SectionHeader 
          icon={isEntregue ? Package : History} 
          title={isEntregue ? "Equipamento Entregue" : "Equipamento Devolvido"} 
          color={isEntregue ? "bg-emerald-500" : "bg-rose-500"} 
        />

        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
          <div className="sm:col-span-2 relative">
            <label className="text-[10px] font-bold text-slate-400 uppercase flex items-center gap-1">
              <Fingerprint size={12}/> Serial / IMEI
            </label>
            <div className="relative mt-1">
              <input 
                disabled={isReadOnly} 
                required 
                className={`w-full p-3 rounded-xl border-2 font-mono font-bold text-sm pr-12 dark:bg-dracula-bg ${isEntregue ? 'border-emerald-200 focus:border-emerald-500' : 'border-rose-200 focus:border-rose-500'}`}
                value={formData[`${prefix}serial` as keyof AssetExchange] as string} 
                onChange={e => setFormData({...formData, [`${prefix}serial`]: e.target.value})}
              />
              {!isReadOnly && (
                <button type="button" onClick={() => setScannerConfig({isOpen: true, target})} className={`absolute right-3 top-1/2 -translate-y-1/2 ${isEntregue ? 'text-emerald-600' : 'text-rose-600'}`}>
                  <ScanLine size={20}/>
                </button>
              )}
            </div>
          </div>

          <div>
            <label className="text-[10px] font-bold text-slate-400 uppercase">Tipo</label>
            <select disabled={isReadOnly} className="w-full p-3 rounded-xl border mt-1 bg-white dark:bg-dracula-bg text-xs" value={formData[`${prefix}tipo` as keyof AssetExchange] as string} onChange={e => setFormData({...formData, [`${prefix}tipo`]: e.target.value})}>
              {EQUIPMENT_TYPES.map(t => <option key={t} value={t}>{t}</option>)}
            </select>
          </div>

          <div>
            <label className="text-[10px] font-bold text-slate-400 uppercase">Marca</label>
            <select disabled={isReadOnly} className="w-full p-3 rounded-xl border mt-1 bg-white dark:bg-dracula-bg text-xs" value={formData[`${prefix}marca` as keyof AssetExchange] as string} onChange={e => setFormData({...formData, [`${prefix}marca`]: e.target.value})}>
              {BRANDS.map(b => <option key={b} value={b}>{b}</option>)}
            </select>
          </div>

          <div>
            <label className="text-[10px] font-bold text-slate-400 uppercase">Modelo</label>
            <select disabled={isReadOnly} className="w-full p-3 rounded-xl border mt-1 bg-white dark:bg-dracula-bg text-xs" value={formData[`${prefix}modelo` as keyof AssetExchange] as string} onChange={e => handleModelChange(e.target.value, target)}>
              {MODELS_LIST.map(m => <option key={m} value={m}>{m}</option>)}
            </select>
          </div>

          <div>
            <label className="text-[10px] font-bold text-slate-400 uppercase">CondiĂ§ĂŁo</label>
            <select disabled={isReadOnly} className="w-full p-3 rounded-xl border mt-1 bg-white dark:bg-dracula-bg text-xs" value={formData[`${prefix}condicao` as keyof AssetExchange] as string} onChange={e => setFormData({...formData, [`${prefix}condicao`]: e.target.value as EquipmentCondition})}>
              <option value={EquipmentCondition.NEW}>Novo</option>
              <option value={EquipmentCondition.USED}>Usado</option>
            </select>
          </div>

          <div className="sm:col-span-2">
            <label className="text-[10px] font-bold text-slate-400 uppercase">Processador</label>
            <select disabled={isReadOnly} className="w-full p-3 rounded-xl border mt-1 bg-white dark:bg-dracula-bg text-xs" value={formData[`${prefix}processador` as keyof AssetExchange] as string} onChange={e => setFormData({...formData, [`${prefix}processador`]: e.target.value})}>
              {PROCESSORS_LIST.map(p => <option key={p} value={p}>{p}</option>)}
            </select>
          </div>

          <div>
            <label className="text-[10px] font-bold text-slate-400 uppercase">MemĂłria RAM</label>
            <select disabled={isReadOnly} className="w-full p-3 rounded-xl border mt-1 bg-white dark:bg-dracula-bg text-xs" value={formData[`${prefix}memoria` as keyof AssetExchange] as string} onChange={e => setFormData({...formData, [`${prefix}memoria`]: e.target.value})}>
              {MEMORY_LIST.map(m => <option key={m} value={m}>{m}</option>)}
            </select>
          </div>

          <div>
            <label className="text-[10px] font-bold text-slate-400 uppercase">Armazenamento (HD/SSD)</label>
            <select disabled={isReadOnly} className="w-full p-3 rounded-xl border mt-1 bg-white dark:bg-dracula-bg text-xs" value={formData[`${prefix}armazenamento` as keyof AssetExchange] as string} onChange={e => setFormData({...formData, [`${prefix}armazenamento`]: e.target.value})}>
              {STORAGE_LIST.map(s => <option key={s} value={s}>{s}</option>)}
            </select>
          </div>

          <div className="sm:col-span-2">
            <label className="text-[10px] font-bold text-slate-400 uppercase mb-2 block">AcessĂłrios</label>
            <div className="grid grid-cols-2 sm:grid-cols-3 gap-2">
              {ACCESSORIES_OPTIONS.map(acc => (
                <button
                  key={acc}
                  type="button"
                  disabled={isReadOnly}
                  onClick={() => handleAccessoryToggle(acc, target)}
                  className={`flex items-center gap-2 p-2 rounded-lg border text-[10px] font-bold transition-all ${
                    (formData[`${prefix}acessorios` as keyof AssetExchange] as string[]).includes(acc)
                      ? 'bg-dracula-purple text-white border-dracula-purple'
                      : 'bg-white dark:bg-dracula-bg text-slate-500 border-slate-200 dark:border-dracula-current hover:border-dracula-purple'
                  }`}
                >
                  <CheckSquare size={14} className={ (formData[`${prefix}acessorios` as keyof AssetExchange] as string[]).includes(acc) ? 'opacity-100' : 'opacity-20' } />
                  {acc}
                </button>
              ))}
            </div>
          </div>
        </div>
      </div>
    );
  };

  return (
    <form onSubmit={handleSubmit} className="p-5 md:p-10 space-y-10">
      {isReadOnly && (
        <div className="bg-amber-50 dark:bg-dracula-orange/10 border border-amber-200 p-4 rounded-2xl flex items-center gap-3">
          <Lock className="text-amber-600" size={20} />
          <span className="text-xs font-bold text-amber-800">DOCUMENTO FINALIZADO E BLOQUEADO</span>
        </div>
      )}

      {/* Dados Colaborador */}
      <section>
        <SectionHeader icon={User} title="InformaĂ§Ă”es do Colaborador" color="bg-dracula-purple" />
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          <div className="relative" ref={adRef}>
            <label className="text-[10px] font-bold text-slate-400 uppercase ml-1">Nome Completo</label>
            <div className="relative mt-1">
              <input disabled={isReadOnly} required className="w-full p-4 rounded-xl border dark:bg-dracula-bg outline-none focus:ring-2 ring-dracula-purple/30 transition-all text-sm pl-10" value={formData.colaborador_nome} onChange={e => handleNameInput(e.target.value)} onFocus={() => setShowSuggestions(true)}/>
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-300" size={16}/>
              {isSearching && <Loader2 className="absolute right-3 top-1/2 -translate-y-1/2 animate-spin text-dracula-purple" size={16}/>}
            </div>
            {showSuggestions && suggestedUsers.length > 0 && (
              <div className="absolute top-full left-0 w-full z-[100] mt-1 bg-white dark:bg-dracula-current rounded-xl shadow-2xl border overflow-hidden">
                {suggestedUsers.map((u, i) => (
                  <button key={i} type="button" onClick={() => { setFormData({...formData, colaborador_nome: u.nome, colaborador_email: u.email}); setShowSuggestions(false); }} className="w-full p-3 text-left hover:bg-slate-50 dark:hover:bg-dracula-bg border-b last:border-0">
                    <div className="font-bold text-xs">{u.nome}</div>
                    <div className="text-[10px] text-slate-400">{u.email}</div>
                  </button>
                ))}
              </div>
            )}
          </div>
          <div>
            <label className="text-[10px] font-bold text-slate-400 uppercase ml-1">E-mail Corporativo</label>
            <input disabled={isReadOnly} type="email" required className="w-full p-4 rounded-xl border mt-1 dark:bg-dracula-bg text-sm" value={formData.colaborador_email} onChange={e => setFormData({...formData, colaborador_email: e.target.value})}/>
          </div>
          <div>
            <label className="text-[10px] font-bold text-slate-400 uppercase ml-1">Data da Troca</label>
            <input disabled={isReadOnly} type="date" required className="w-full p-4 rounded-xl border mt-1 dark:bg-dracula-bg text-sm" value={formData.data_troca} onChange={e => setFormData({...formData, data_troca: e.target.value})}/>
          </div>
        </div>
      </section>

      {/* Grid de Equipamentos */}
      <div className="grid grid-cols-1 xl:grid-cols-2 gap-10">
        <EquipmentSection target="entregue" />
        <EquipmentSection target="devolvido" />
      </div>

      <section>
        <SectionHeader icon={MousePointer2} title="ObservaĂ§Ă”es e Notas" color="bg-slate-400" />
        <textarea disabled={isReadOnly} className="w-full p-4 rounded-2xl border dark:bg-dracula-bg h-24 text-sm" value={formData.observacoes} onChange={e => setFormData({...formData, observacoes: e.target.value})} placeholder="Adicione detalhes relevantes sobre a troca..."/>
      </section>

      <div className="flex flex-col sm:flex-row justify-end gap-4 pt-4">
        <button type="button" onClick={onCancel} className="px-8 py-4 font-bold text-slate-400 hover:text-slate-600">Voltar</button>
        {!isReadOnly && (
          <button type="submit" disabled={isSubmitting} className="px-10 py-4 bg-dracula-purple text-white rounded-2xl font-bold shadow-xl flex items-center justify-center gap-2 transition-transform active:scale-95">
            {isSubmitting ? <Loader2 className="animate-spin" size={20}/> : <Send size={20}/>}
            {editingExchange ? 'Salvar AlteraĂ§Ă”es' : 'Gravar Registro'}
          </button>
        )}
      </div>

      {scannerConfig.isOpen && (
        <BarcodeScannerModal 
          title={scannerConfig.target === 'entregue' ? 'Escanear Serial Entregue' : 'Escanear Serial Devolvido'}
          onScan={(text) => {
            const prefix = scannerConfig.target === 'entregue' ? 'entregue_' : 'devolvido_';
            setFormData({...formData, [`${prefix}serial`]: text});
            setScannerConfig({...scannerConfig, isOpen: false});
          }}
          onClose={() => setScannerConfig({...scannerConfig, isOpen: false})}
        />
      )}
    </form>
  );
};

export default AssetForm;

import React, { useState, useEffect } from 'react';
import { PlusCircle, ClipboardList, LogOut, CheckCircle2, AlertCircle, Mail, Loader2, HardDrive, PanelLeftClose, PanelLeftOpen, Image as ImageIcon, Sun, Moon, Settings, ShieldCheck } from 'lucide-react';
import { View, AssetExchange, MockEmail, LogoPreference } from './types';
import AssetForm from './components/AssetForm';
import InventoryTable from './components/InventoryTable';
import MockInbox from './components/MockInbox';
import SenderSignatureModal from './components/SenderSignatureModal';
import { apiService } from './services/apiService';
import { m365Service } from './services/m365Service';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>('form');
  const [exchanges, setExchanges] = useState<AssetExchange[]>([]);
  const [emails, setEmails] = useState<MockEmail[]>([]);
  const [editingExchange, setEditingExchange] = useState<AssetExchange | null>(null);
  const [signingExchange, setSigningExchange] = useState<AssetExchange | null>(null);
  const [notification, setNotification] = useState<{message: string, type: 'success' | 'error'} | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [m365Account, setM365Account] = useState<any>(null);
  const [showConfigModal, setShowConfigModal] = useState(false);

  const [isSidebarVisible, setIsSidebarVisible] = useState(() => {
    const saved = localStorage.getItem('sidebar_visible');
    return saved !== null ? JSON.parse(saved) : true;
  });

  const [theme, setTheme] = useState<'light' | 'dark'>(() => {
    const saved = localStorage.getItem('theme');
    return (saved === 'light' || saved === 'dark') ? saved : 'light';
  });

  const [logoPref, setLogoPref] = useState<LogoPreference>(() => {
    const saved = localStorage.getItem('logo_preference');
    return (saved === 'cirion' || saved === 'none') ? saved : 'cirion';
  });

  useEffect(() => {
    loadData();
    checkM365();
    const savedEmails = localStorage.getItem('mock_emails');
    if (savedEmails) setEmails(JSON.parse(savedEmails));
  }, []);

  const loadData = async () => {
    const data = await apiService.getAll();
    setExchanges(data);
  };

  const checkM365 = async () => {
    const account = await m365Service.getAccount();
    setM365Account(account);
  };

  const handleM365Login = async () => {
    try {
      const account = await m365Service.login();
      setM365Account(account);
      showNotification("Conectado ao Microsoft 365!");
    } catch (err) {
      setShowConfigModal(true);
    }
  };

  const handleM365Logout = async () => {
    await m365Service.logout();
    setM365Account(null);
    showNotification("Desconectado do Microsoft 365.", "error");
  };

  useEffect(() => {
    localStorage.setItem('mock_emails', JSON.stringify(emails));
  }, [emails]);

  useEffect(() => {
    localStorage.setItem('logo_preference', logoPref);
  }, [logoPref]);

  useEffect(() => {
    localStorage.setItem('sidebar_visible', JSON.stringify(isSidebarVisible));
  }, [isSidebarVisible]);

  useEffect(() => {
    localStorage.setItem('theme', theme);
    const root = window.document.documentElement;
    if (theme === 'dark') {
      root.classList.add('dark');
    } else {
      root.classList.remove('dark');
    }
  }, [theme]);

  const showNotification = (message: string, type: 'success' | 'error' = 'success') => {
    setNotification({ message, type });
    setTimeout(() => setNotification(null), 5000);
  };

  const handleSaveExchange = async (exchange: AssetExchange) => {
    setIsLoading(true);
    try {
      await apiService.save(exchange);
      await loadData();
      setEditingExchange(null);
      setCurrentView('inventory');
      showNotification("Registro gravado.");
    } catch (error) {
      showNotification("Erro ao salvar.", "error");
    } finally {
      setIsLoading(false);
    }
  };

  const handleDelete = async (id: string) => {
    if (window.confirm("Deseja excluir permanentemente este registro?")) {
      setIsLoading(true);
      try {
        await apiService.delete(id);
        await loadData();
        showNotification("Registro removido.", "success");
      } catch (error) {
        showNotification("Erro ao remover.", "error");
      } finally {
        setIsLoading(false);
      }
    }
  };

  const handleSignSender = async (id: string, signature: string) => {
    const exchange = exchanges.find(e => e.id === id);
    if (!exchange) return;
    const updated: AssetExchange = { ...exchange, assinatura_ti: signature, status: 'pending_receiver' };
    await apiService.save(updated);
    await loadData();
    const newEmail: MockEmail = {
      id: Math.random().toString(36).substr(2, 9),
      exchangeId: id,
      from: 'TI Infra - AssetFlow <infra@cirion.com>',
      to: exchange.colaborador_email,
      subject: `[AĂĂO NECESSĂRIA] Termo de Troca - ${exchange.colaborador_nome}`,
      body: `OlĂĄ ${exchange.colaborador_nome},\n\nRevise e assine o termo em anexo.`,
      sentAt: new Date().toISOString(),
      read: false,
      attachment: true
    };
    setEmails([newEmail, ...emails]);
    setSigningExchange(null);
    showNotification("Termo enviado.");
  };

  const navTo = (view: View) => {
    setEditingExchange(null);
    setSigningExchange(null);
    setCurrentView(view);
  };

  return (
    <div className="flex h-screen bg-slate-50 dark:bg-dracula-bg text-slate-900 dark:text-dracula-fg overflow-hidden">

      {/* Sidebar adaptativa - Layout Original */}
      <aside className={`bg-slate-900 dark:bg-dracula-darker text-white flex-shrink-0 flex flex-col shadow-2xl transition-all duration-300 ease-in-out ${isSidebarVisible ? 'w-80' : 'w-0 opacity-0 overflow-hidden'}`}>
        <div className="p-8 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <HardDrive className="text-dracula-purple" size={24} />
            <h1 className="text-xl font-bold">AssetFlow</h1>
          </div>
          <button onClick={() => setIsSidebarVisible(false)} className="p-2 hover:bg-slate-800 rounded-lg text-slate-500">
            <PanelLeftClose size={18} />
          </button>
        </div>

        <nav className="flex-1 px-4 py-6 space-y-2 overflow-y-auto">
          <NavItem icon={PlusCircle} label="Nova Troca" active={currentView === 'form'} onClick={() => navTo('form')} />
          <NavItem icon={ClipboardList} label="InventĂĄrio" active={currentView === 'inventory'} onClick={() => navTo('inventory')} />
          <NavItem icon={Mail} label="Outlook" active={currentView === 'inbox'} onClick={() => navTo('inbox')} badge={emails.some(e => !e.read)} />
        </nav>

        <div className="p-6 border-t border-slate-800 space-y-4">
           <div className="flex items-center justify-between mb-4">
             <button onClick={() => setTheme(theme === 'light' ? 'dark' : 'light')} className="p-2 bg-slate-800 rounded-xl hover:text-dracula-purple transition-colors">
               {theme === 'light' ? <Moon size={18} /> : <Sun size={18} />}
             </button>
             <button onClick={() => setShowConfigModal(true)} className="p-2 bg-slate-800 rounded-xl hover:text-dracula-purple transition-colors">
               <Settings size={18} />
             </button>
           </div>
           <button className="w-full flex items-center gap-3 px-4 py-3 text-xs text-slate-500 hover:text-rose-400 transition-colors bg-white/5 rounded-xl">
              <LogOut size={16} /> <span>Sair do Sistema</span>
           </button>
        </div>
      </aside>

      {/* Main Area */}
      <main className="flex-1 flex flex-col min-w-0 overflow-hidden relative">

        {/* BotĂŁo de abrir sidebar quando oculta */}
        {!isSidebarVisible && (
          <button 
            onClick={() => setIsSidebarVisible(true)}
            className="absolute left-6 top-8 z-50 p-2.5 bg-slate-900 text-white rounded-xl shadow-2xl hover:scale-105 transition-all"
            title="Abrir Menu"
          >
            <PanelLeftOpen size={24} />
          </button>
        )}

        {notification && (
          <div className="fixed top-6 right-6 z-[100] animate-in slide-in-from-right duration-300">
            <div className={`px-6 py-4 rounded-2xl shadow-2xl border flex items-center gap-3 ${notification.type === 'success' ? 'bg-emerald-50 border-emerald-200 text-emerald-800 dark:bg-dracula-green/20 dark:text-dracula-green' : 'bg-rose-50 border-rose-200 text-rose-800 dark:bg-dracula-red/20 dark:text-dracula-red'}`}>
              {notification.type === 'success' ? <CheckCircle2 size={20} /> : <AlertCircle size={20} />}
              <span className="font-bold text-sm">{notification.message}</span>
            </div>
          </div>
        )}

        <div className="flex-1 overflow-y-auto p-4 md:p-10 space-y-8 transition-all duration-300">
          <header className="space-y-1">
            <h2 className="text-3xl font-extrabold tracking-tight">
              {currentView === 'form' ? 'GestĂŁo de Ativos' : currentView === 'inventory' ? 'InventĂĄrio' : 'Outlook'}
            </h2>
            <p className="text-slate-500 text-sm font-medium">Controle de equipamentos TI Cirion</p>
          </header>

          <div className="bg-white dark:bg-dracula-darker rounded-[2.5rem] shadow-2xl border border-slate-100 dark:border-dracula-current min-h-[600px] overflow-hidden">
            {currentView === 'form' && (
              <AssetForm 
                onSave={handleSaveExchange} 
                editingExchange={editingExchange} 
                onCancel={() => navTo('inventory')} 
                m365Connected={!!m365Account}
              />
            )}
            {currentView === 'inventory' && (
              <InventoryTable 
                exchanges={exchanges} 
                onDelete={handleDelete} 
                onEdit={(ex) => { setEditingExchange(ex); setCurrentView('form'); }} 
                onNotify={showNotification}
                onSignStart={setSigningExchange}
                onBulkImport={(data) => { exchanges.push(...data); loadData(); }}
                logoPref={logoPref}
              />
            )}
            {currentView === 'inbox' && (
              <MockInbox 
                emails={emails} 
                onUpdateEmails={setEmails} 
                exchanges={exchanges}
                onSignReceiver={(id, sig) => {
                  const ex = exchanges.find(e => e.id === id);
                  if(ex) { ex.status = 'completed'; ex.assinatura_colaborador = sig; apiService.save(ex); loadData(); showNotification("Termo finalizado!"); }
                }}
                logoPref={logoPref}
              />
            )}
          </div>
        </div>
      </main>

      {signingExchange && <SenderSignatureModal exchange={signingExchange} onClose={() => setSigningExchange(null)} onConfirm={handleSignSender} />}

      {showConfigModal && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-4 bg-slate-900/90 backdrop-blur-md">
           <div className="bg-white dark:bg-dracula-bg w-full max-w-sm rounded-[2rem] p-8 border shadow-2xl">
              <h3 className="text-xl font-bold mb-6">Configurar Microsoft 365</h3>
              <div className="space-y-4">
                 <input id="cfg_cid" placeholder="Application Client ID" className="w-full p-4 rounded-xl border dark:bg-dracula-darker text-xs font-mono"/>
                 <input id="cfg_tid" placeholder="Directory Tenant ID" className="w-full p-4 rounded-xl border dark:bg-dracula-darker text-xs font-mono"/>
                 <div className="flex gap-3 pt-4">
                    <button onClick={() => setShowConfigModal(false)} className="flex-1 py-3 text-slate-400 font-bold">Cancelar</button>
                    <button onClick={() => {
                       const c = (document.getElementById('cfg_cid') as HTMLInputElement).value;
                       const t = (document.getElementById('cfg_tid') as HTMLInputElement).value;
                       if(c && t) { m365Service.updateConfig(c, t); setShowConfigModal(false); showNotification("Salvo!"); }
                    }} className="flex-1 py-3 bg-dracula-purple text-white rounded-xl font-bold transition-transform active:scale-95">Salvar</button>
                 </div>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

const NavItem = ({ icon: Icon, label, active, onClick, badge }: any) => (
  <button
    onClick={onClick}
    className={`w-full flex items-center gap-4 px-4 py-4 rounded-xl transition-all relative ${active ? 'bg-dracula-purple text-white shadow-xl shadow-dracula-purple/20' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}
  >
    <Icon size={20} />
    <span className="font-bold text-sm">{label}</span>
    {badge && <div className="absolute right-4 w-2 h-2 bg-dracula-pink rounded-full" />}
  </button>
);

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { AssetExchange, EquipmentCondition } from '../types';
import { EQUIPMENT_TYPES, BRANDS, MODELS_LIST, PROCESSORS_LIST, MODEL_PROCESSOR_MAP, MEMORY_LIST, STORAGE_LIST, AD_USERS } from '../constants';
import { User, Package, History, Send, ScanLine, Lock, MousePointer2, Loader2, Search, Fingerprint, CheckSquare } from 'lucide-react';
import BarcodeScannerModal from './BarcodeScannerModal';
import { m365Service } from '../services/m365Service';

interface AssetFormProps {
  onSave: (exchange: AssetExchange) => Promise<void> | void;
  editingExchange?: AssetExchange | null;
  onCancel?: () => void;
  m365Connected?: boolean;
}

const ACCESSORIES_OPTIONS = ["Mouse", "Mochila", "Teclado", "DockStation", "Headset", "Monitor"];

// Componente Header Auxiliar
const SectionHeader = ({ icon: Icon, title, color }: any) => (
  <div className="flex items-center gap-3 mb-6 pb-2 border-b border-slate-100 dark:border-dracula-current">
    <div className={`p-2 rounded-lg ${color} shadow-sm`}><Icon size={18} className="text-white" /></div>
    <h3 className="text-lg font-bold">{title}</h3>
  </div>
);

// Movi o EquipmentSection para fora para evitar que o React recrie o componente e perca o foco do input
interface EquipmentSectionProps {
  target: 'entregue' | 'devolvido';
  formData: AssetExchange;
  setFormData: React.Dispatch<React.SetStateAction<AssetExchange>>;
  isReadOnly: boolean;
  onScanClick: (target: 'entregue' | 'devolvido') => void;
  onModelChange: (model: string, target: 'entregue' | 'devolvido') => void;
  onAccessoryToggle: (acc: string, target: 'entregue' | 'devolvido') => void;
}

const EquipmentSection: React.FC<EquipmentSectionProps> = ({ 
  target, formData, setFormData, isReadOnly, onScanClick, onModelChange, onAccessoryToggle 
}) => {
  const prefix = target === 'entregue' ? 'entregue_' : 'devolvido_';
  const isEntregue = target === 'entregue';

  return (
    <div className="p-6 bg-slate-50 dark:bg-dracula-bg/40 rounded-3xl border border-slate-100 dark:border-dracula-current space-y-6">
      <SectionHeader 
        icon={isEntregue ? Package : History} 
        title={isEntregue ? "Equipamento Entregue" : "Equipamento Devolvido"} 
        color={isEntregue ? "bg-emerald-500" : "bg-rose-500"} 
      />

      <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
        <div className="sm:col-span-2 relative">
          <label className="text-[10px] font-bold text-slate-400 uppercase flex items-center gap-1">
            <Fingerprint size={12}/> Serial / IMEI
          </label>
          <div className="relative mt-1">
            <input 
              autoComplete="off"
              disabled={isReadOnly} 
              required 
              className={`w-full p-3 rounded-xl border-2 font-mono font-bold text-sm pr-12 dark:bg-dracula-bg transition-all outline-none ${isEntregue ? 'border-emerald-100 focus:border-emerald-500 bg-white' : 'border-rose-100 focus:border-rose-500 bg-white'}`}
              value={formData[`${prefix}serial` as keyof AssetExchange] as string} 
              onChange={e => setFormData(prev => ({...prev, [`${prefix}serial`]: e.target.value}))}
            />
            {!isReadOnly && (
              <button type="button" onClick={() => onScanClick(target)} className={`absolute right-3 top-1/2 -translate-y-1/2 ${isEntregue ? 'text-emerald-600' : 'text-rose-600'}`}>
                <ScanLine size={20}/>
              </button>
            )}
          </div>
        </div>

        <div>
          <label className="text-[10px] font-bold text-slate-400 uppercase">Tipo</label>
          <select disabled={isReadOnly} className="w-full p-3 rounded-xl border mt-1 bg-white dark:bg-dracula-bg text-xs" value={formData[`${prefix}tipo` as keyof AssetExchange] as string} onChange={e => setFormData({...formData, [`${prefix}tipo`]: e.target.value})}>
            {EQUIPMENT_TYPES.map(t => <option key={t} value={t}>{t}</option>)}
          </select>
        </div>

        <div>
          <label className="text-[10px] font-bold text-slate-400 uppercase">Marca</label>
          <select disabled={isReadOnly} className="w-full p-3 rounded-xl border mt-1 bg-white dark:bg-dracula-bg text-xs" value={formData[`${prefix}marca` as keyof AssetExchange] as string} onChange={e => setFormData({...formData, [`${prefix}marca`]: e.target.value})}>
            {BRANDS.map(b => <option key={b} value={b}>{b}</option>)}
          </select>
        </div>

        <div>
          <label className="text-[10px] font-bold text-slate-400 uppercase">Modelo</label>
          <select disabled={isReadOnly} className="w-full p-3 rounded-xl border mt-1 bg-white dark:bg-dracula-bg text-xs" value={formData[`${prefix}modelo` as keyof AssetExchange] as string} onChange={e => onModelChange(e.target.value, target)}>
            {MODELS_LIST.map(m => <option key={m} value={m}>{m}</option>)}
          </select>
        </div>

        <div>
          <label className="text-[10px] font-bold text-slate-400 uppercase">CondiĂ§ĂŁo</label>
          <select disabled={isReadOnly} className="w-full p-3 rounded-xl border mt-1 bg-white dark:bg-dracula-bg text-xs" value={formData[`${prefix}condicao` as keyof AssetExchange] as string} onChange={e => setFormData({...formData, [`${prefix}condicao`]: e.target.value as EquipmentCondition})}>
            <option value={EquipmentCondition.NEW}>Novo</option>
            <option value={EquipmentCondition.USED}>Usado</option>
          </select>
        </div>

        <div className="sm:col-span-2">
          <label className="text-[10px] font-bold text-slate-400 uppercase">Processador</label>
          <select disabled={isReadOnly} className="w-full p-3 rounded-xl border mt-1 bg-white dark:bg-dracula-bg text-xs" value={formData[`${prefix}processador` as keyof AssetExchange] as string} onChange={e => setFormData({...formData, [`${prefix}processador`]: e.target.value})}>
            {PROCESSORS_LIST.map(p => <option key={p} value={p}>{p}</option>)}
          </select>
        </div>

        <div>
          <label className="text-[10px] font-bold text-slate-400 uppercase">MemĂłria RAM</label>
          <select disabled={isReadOnly} className="w-full p-3 rounded-xl border mt-1 bg-white dark:bg-dracula-bg text-xs" value={formData[`${prefix}memoria` as keyof AssetExchange] as string} onChange={e => setFormData({...formData, [`${prefix}memoria`]: e.target.value})}>
            {MEMORY_LIST.map(m => <option key={m} value={m}>{m}</option>)}
          </select>
        </div>

        <div>
          <label className="text-[10px] font-bold text-slate-400 uppercase">Armazenamento (HD/SSD)</label>
          <select disabled={isReadOnly} className="w-full p-3 rounded-xl border mt-1 bg-white dark:bg-dracula-bg text-xs" value={formData[`${prefix}armazenamento` as keyof AssetExchange] as string} onChange={e => setFormData({...formData, [`${prefix}armazenamento`]: e.target.value})}>
            {STORAGE_LIST.map(s => <option key={s} value={s}>{s}</option>)}
          </select>
        </div>

        <div className="sm:col-span-2">
          <label className="text-[10px] font-bold text-slate-400 uppercase mb-2 block">AcessĂłrios</label>
          <div className="grid grid-cols-2 sm:grid-cols-3 gap-2">
            {ACCESSORIES_OPTIONS.map(acc => (
              <button
                key={acc}
                type="button"
                disabled={isReadOnly}
                onClick={() => onAccessoryToggle(acc, target)}
                className={`flex items-center gap-2 p-2 rounded-lg border text-[10px] font-bold transition-all ${
                  (formData[`${prefix}acessorios` as keyof AssetExchange] as string[]).includes(acc)
                    ? 'bg-dracula-purple text-white border-dracula-purple shadow-md'
                    : 'bg-white dark:bg-dracula-bg text-slate-500 border-slate-200 dark:border-dracula-current hover:border-dracula-purple'
                }`}
              >
                <CheckSquare size={14} className={ (formData[`${prefix}acessorios` as keyof AssetExchange] as string[]).includes(acc) ? 'opacity-100' : 'opacity-20' } />
                {acc}
              </button>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};

const AssetForm: React.FC<AssetFormProps> = ({ onSave, editingExchange, onCancel, m365Connected }) => {
  const isReadOnly = editingExchange?.status === 'completed';
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [showSuggestions, setShowSuggestions] = useState(false);
  const [suggestedUsers, setSuggestedUsers] = useState<any[]>([]);
  const [isSearching, setIsSearching] = useState(false);
  const adRef = useRef<HTMLDivElement>(null);
  const searchTimeoutRef = useRef<number | null>(null);

  const [formData, setFormData] = useState<AssetExchange>({
    id: '',
    status: 'draft',
    timestamp: Date.now(),
    colaborador_nome: '',
    colaborador_email: '',
    data_troca: new Date().toISOString().split('T')[0],
    observacoes: '',
    entregue_tipo: EQUIPMENT_TYPES[0],
    entregue_marca: BRANDS[0],
    entregue_modelo: MODELS_LIST[0],
    entregue_serial: '',
    entregue_processador: PROCESSORS_LIST[0],
    entregue_condicao: EquipmentCondition.NEW,
    entregue_memoria: MEMORY_LIST[2],
    entregue_armazenamento: STORAGE_LIST[3],
    entregue_acessorios: [],
    devolvido_tipo: EQUIPMENT_TYPES[0],
    devolvido_marca: BRANDS[0],
    devolvido_modelo: MODELS_LIST[0],
    devolvido_serial: '',
    devolvido_processador: PROCESSORS_LIST[0],
    devolvido_condicao: EquipmentCondition.USED,
    devolvido_memoria: MEMORY_LIST[2],
    devolvido_armazenamento: STORAGE_LIST[3],
    devolvido_acessorios: []
  });

  const [scannerConfig, setScannerConfig] = useState<{ isOpen: boolean; target: 'entregue' | 'devolvido' }>({
    isOpen: false,
    target: 'entregue'
  });

  useEffect(() => {
    if (editingExchange) setFormData({ ...editingExchange });
  }, [editingExchange]);

  useEffect(() => {
    const handleClickOutside = (e: MouseEvent) => {
      if (adRef.current && !adRef.current.contains(e.target as Node)) setShowSuggestions(false);
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleNameInput = (value: string) => {
    setFormData(prev => ({ ...prev, colaborador_nome: value }));
    if (value.length < 2) {
      setShowSuggestions(false);
      return;
    }
    setShowSuggestions(true);
    if (searchTimeoutRef.current) clearTimeout(searchTimeoutRef.current);
    searchTimeoutRef.current = window.setTimeout(async () => {
      setIsSearching(true);
      try {
        const results = m365Connected ? await m365Service.searchUsers(value) : 
          AD_USERS.filter(u => u.nome.toLowerCase().includes(value.toLowerCase())).slice(0, 5);
        setSuggestedUsers(results);
      } finally {
        setIsSearching(false);
      }
    }, 400);
  };

  const handleModelChange = (model: string, target: 'entregue' | 'devolvido') => {
    const proc = MODEL_PROCESSOR_MAP[model];
    const prefix = target === 'entregue' ? 'entregue_' : 'devolvido_';
    setFormData(prev => ({ 
      ...prev, 
      [`${prefix}modelo`]: model,
      [`${prefix}processador`]: proc || prev[`${prefix}processador` as keyof AssetExchange]
    }));
  };

  const handleAccessoryToggle = (acc: string, target: 'entregue' | 'devolvido') => {
    const prefix = target === 'entregue' ? 'entregue_acessorios' : 'devolvido_acessorios';
    const current = formData[prefix] as string[];
    const updated = current.includes(acc) ? current.filter(a => a !== acc) : [...current, acc];
    setFormData(prev => ({ ...prev, [prefix]: updated }));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (isSubmitting) return;
    setIsSubmitting(true);
    try {
      const payload = { ...formData, id: formData.id || Math.random().toString(36).substr(2, 9).toUpperCase() };
      await onSave(payload);
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <form onSubmit={handleSubmit} className="p-5 md:p-10 space-y-10">
      {isReadOnly && (
        <div className="bg-amber-50 dark:bg-dracula-orange/10 border border-amber-200 p-4 rounded-2xl flex items-center gap-3">
          <Lock className="text-amber-600" size={20} />
          <span className="text-xs font-bold text-amber-800 uppercase tracking-widest">Documento Finalizado e Bloqueado</span>
        </div>
      )}

      {/* Dados Colaborador */}
      <section>
        <SectionHeader icon={User} title="InformaĂ§Ă”es do Colaborador" color="bg-dracula-purple" />
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          <div className="relative" ref={adRef}>
            <label className="text-[10px] font-bold text-slate-400 uppercase ml-1">Nome Completo</label>
            <div className="relative mt-1">
              <input disabled={isReadOnly} required className="w-full p-4 rounded-xl border-2 border-slate-100 focus:border-dracula-purple dark:bg-dracula-bg outline-none transition-all text-sm pl-10" value={formData.colaborador_nome} onChange={e => handleNameInput(e.target.value)} onFocus={() => setShowSuggestions(true)}/>
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-300" size={16}/>
              {isSearching && <Loader2 className="absolute right-3 top-1/2 -translate-y-1/2 animate-spin text-dracula-purple" size={16}/>}
            </div>
            {showSuggestions && suggestedUsers.length > 0 && (
              <div className="absolute top-full left-0 w-full z-[100] mt-1 bg-white dark:bg-dracula-current rounded-xl shadow-2xl border overflow-hidden">
                {suggestedUsers.map((u, i) => (
                  <button key={i} type="button" onClick={() => { setFormData(prev => ({...prev, colaborador_nome: u.nome, colaborador_email: u.email})); setShowSuggestions(false); }} className="w-full p-3 text-left hover:bg-slate-50 dark:hover:bg-dracula-bg border-b last:border-0">
                    <div className="font-bold text-xs">{u.nome}</div>
                    <div className="text-[10px] text-slate-400">{u.email}</div>
                  </button>
                ))}
              </div>
            )}
          </div>
          <div>
            <label className="text-[10px] font-bold text-slate-400 uppercase ml-1">E-mail Corporativo</label>
            <input disabled={isReadOnly} type="email" required className="w-full p-4 rounded-xl border-2 border-slate-100 focus:border-dracula-purple mt-1 dark:bg-dracula-bg text-sm outline-none transition-all" value={formData.colaborador_email} onChange={e => setFormData(prev => ({...prev, colaborador_email: e.target.value}))}/>
          </div>
          <div>
            <label className="text-[10px] font-bold text-slate-400 uppercase ml-1">Data da Troca</label>
            <input disabled={isReadOnly} type="date" required className="w-full p-4 rounded-xl border-2 border-slate-100 focus:border-dracula-purple mt-1 dark:bg-dracula-bg text-sm outline-none transition-all" value={formData.data_troca} onChange={e => setFormData(prev => ({...prev, data_troca: e.target.value}))}/>
          </div>
        </div>
      </section>

      {/* Grid de Equipamentos */}
      <div className="grid grid-cols-1 xl:grid-cols-2 gap-10">
        <EquipmentSection 
          target="entregue" 
          formData={formData} 
          setFormData={setFormData} 
          isReadOnly={isReadOnly}
          onScanClick={(target) => setScannerConfig({isOpen: true, target})}
          onModelChange={handleModelChange}
          onAccessoryToggle={handleAccessoryToggle}
        />
        <EquipmentSection 
          target="devolvido" 
          formData={formData} 
          setFormData={setFormData} 
          isReadOnly={isReadOnly}
          onScanClick={(target) => setScannerConfig({isOpen: true, target})}
          onModelChange={handleModelChange}
          onAccessoryToggle={handleAccessoryToggle}
        />
      </div>

      <section>
        <SectionHeader icon={MousePointer2} title="ObservaĂ§Ă”es e Notas" color="bg-slate-400" />
        <textarea disabled={isReadOnly} className="w-full p-4 rounded-2xl border-2 border-slate-100 focus:border-dracula-purple dark:bg-dracula-bg h-24 text-sm outline-none transition-all" value={formData.observacoes} onChange={e => setFormData(prev => ({...prev, observacoes: e.target.value}))} placeholder="Adicione detalhes relevantes sobre a troca..."/>
      </section>

      <div className="flex flex-col sm:flex-row justify-end gap-4 pt-4">
        <button type="button" onClick={onCancel} className="px-8 py-4 font-bold text-slate-400 hover:text-slate-600 transition-colors">Voltar</button>
        {!isReadOnly && (
          <button type="submit" disabled={isSubmitting} className="px-10 py-4 bg-dracula-purple text-white rounded-2xl font-bold shadow-xl flex items-center justify-center gap-2 transition-transform active:scale-95 disabled:opacity-50">
            {isSubmitting ? <Loader2 className="animate-spin" size={20}/> : <Send size={20}/>}
            {editingExchange ? 'Salvar AlteraĂ§Ă”es' : 'Gravar Registro'}
          </button>
        )}
      </div>

      {scannerConfig.isOpen && (
        <BarcodeScannerModal 
          title={scannerConfig.target === 'entregue' ? 'Escanear Serial Entregue' : 'Escanear Serial Devolvido'}
          onScan={(text) => {
            const prefix = scannerConfig.target === 'entregue' ? 'entregue_' : 'devolvido_';
            setFormData(prev => ({...prev, [`${prefix}serial`]: text}));
            setScannerConfig(prev => ({...prev, isOpen: false}));
          }}
          onClose={() => setScannerConfig(prev => ({...prev, isOpen: false}))}
        />
      )}
    </form>
  );
};

