import { jsPDF } from 'jspdf';
import { AssetExchange, LogoPreference } from '../types';

export const generateAssetPDF = (exchange: AssetExchange, logoPref: LogoPreference = 'cirion') => {
  try {
    const doc = new jsPDF({
      orientation: 'p',
      unit: 'mm',
      format: 'a4'
    });

    // Cores extraĂ­das para o efeito 3D e visual
    const cirionBlue = "#1a5edb"; 
    const cirionShadow = "#0a3a8a"; 
    const boxBlue = "#00158a"; 
    const inkBlue = "#003087";

    const renderPage = (isEntregue: boolean) => {
      const prefix = isEntregue ? 'entregue_' : 'devolvido_';

      // 1. RenderizaĂ§ĂŁo condicional do logotipo
      if (logoPref === 'cirion') {
        const startX = 25;
        const startY = 25;
        const mainText = "CIRION";
        const subText = "TECHNOLOGIES";

        // Parte Principal
        doc.setFont("helvetica", "bold");
        doc.setFontSize(28);
        doc.setTextColor(cirionShadow);
        doc.text(mainText, startX + 0.4, startY + 0.4);
        doc.setTextColor(cirionBlue);
        doc.text(mainText, startX, startY);

        // Subtexto
        doc.setFontSize(9);
        doc.setCharSpace(1.5);
        doc.setTextColor(cirionShadow);
        doc.text(subText, startX + 0.8, startY + 7.3);
        doc.setTextColor(cirionBlue);
        doc.text(subText, startX + 0.5, startY + 7);
        doc.setCharSpace(0);
      }

      // TĂ­tulo e Checkboxes
      doc.setFontSize(11);
      doc.setTextColor(boxBlue);
      const titleText = logoPref === 'cirion' ? "DeclaraĂ§ĂŁo de Equipamento Cirion" : "DeclaraĂ§ĂŁo de Entrega de Equipamento";
      doc.text(titleText, 85, 20);

      doc.setDrawColor(boxBlue);
      doc.setLineWidth(0.3);

      // Checkbox Entrega
      doc.rect(85, 23, 3, 3);
      if (isEntregue) doc.text("x", 86, 25.5);
      doc.setFontSize(9);
      doc.text("Entrega", 90, 25.5);

      // Checkbox DevoluĂ§ĂŁo
      doc.rect(110, 23, 3, 3);
      if (!isEntregue) doc.text("x", 111, 25.5);
      doc.text("DevoluĂ§ĂŁo", 115, 25.5);

      // 2. Texto de IntroduĂ§ĂŁo
      doc.setFontSize(9);
      doc.setTextColor(0, 0, 0);
      doc.setFont("helvetica", "normal");
      doc.text("Eu, ", 20, 40);
      doc.line(26, 40.5, 95, 40.5);
      doc.setFont("helvetica", "bold");
      doc.text(exchange.colaborador_nome, 28, 40);
      doc.setFont("helvetica", "normal");
      doc.text("declaro ter recebido/devolvido o", 97, 40);
      doc.text("equipamento e acessĂłrios abaixo descritos, em perfeitas condiĂ§Ă”es de funcionamento.", 20, 45);

      // 3. Campos de Dados
      let y = 55;
      const LABEL_X = 20;
      const FIELD_X = 40;
      const BOX_WIDTH = 100;

      const drawField = (label: string, value: string, width: number = BOX_WIDTH, customX: number = FIELD_X) => {
        doc.setFont("helvetica", "bold");
        doc.setFontSize(11);
        doc.setTextColor(0, 0, 0);
        doc.text(label, LABEL_X, y + 4.5);

        doc.setDrawColor(boxBlue);
        doc.rect(customX, y, width, 6);
        doc.setFont("helvetica", "normal");
        doc.text(value || "", customX + 2, y + 4.5);
        y += 8;
      };

      drawField("Tipo:", String(exchange[`${prefix}tipo` as keyof AssetExchange]));
      drawField("Marca:", String(exchange[`${prefix}marca` as keyof AssetExchange]));
      drawField("Modelo:", String(exchange[`${prefix}modelo` as keyof AssetExchange]));
      drawField("NĂșmero de Serie / Imei:", String(exchange[`${prefix}serial` as keyof AssetExchange]), 82, 68);
      drawField("Estado:", String(exchange[`${prefix}condicao` as keyof AssetExchange]), 25);

      y += 2;
      doc.setFont("helvetica", "bold");
      doc.text("Tamanho do HD:", 20, y + 4.5);
      doc.rect(58, y, 30, 6);
      doc.setFont("helvetica", "normal");
      doc.text(String(exchange[`${prefix}armazenamento` as keyof AssetExchange]), 60, y + 4.5);
      y += 8;

      drawField("Processador:", String(exchange[`${prefix}processador` as keyof AssetExchange]), 150, 50);

      doc.setFont("helvetica", "bold");
      doc.text("MemĂłria:", 20, y + 4.5);
      doc.rect(42, y, 25, 6);
      doc.setFont("helvetica", "normal");
      doc.text(String(exchange[`${prefix}memoria` as keyof AssetExchange]), 44, y + 4.5);
      y += 15;

      // 4. Caixa de AcessĂłrios
      doc.setFontSize(12);
      doc.setFont("helvetica", "bold");
      doc.text("AcessĂłrios:", 105, y, { align: "center" });
      y += 4;

      doc.setDrawColor(boxBlue);
      doc.rect(45, y, 120, 20);

      const accessories = ["Mouse", "Teclado", "Headset", "Mochila", "DockStation", "Monitor"];
      const selectedAccs = (exchange[`${prefix}acessorios` as keyof AssetExchange] as string[]) || [];

      doc.setFontSize(10);
      doc.setFont("helvetica", "normal");
      let accX = 65;
      let accY = y + 5;

      accessories.forEach((acc, index) => {
        doc.rect(accX, accY - 2.5, 3, 3);
        if (selectedAccs.includes(acc)) doc.text("x", accX + 0.8, accY);
        doc.text(acc, accX + 5, accY);

        if (index === 2) {
          accX = 110;
          accY = y + 5;
        } else {
          accY += 6;
        }
      });

      y += 35;

      // 5. ObservaĂ§Ă”es
      doc.setFontSize(11);
      doc.setFont("helvetica", "bold");
      doc.text("Obs:", 20, y + 4.5);
      doc.rect(32, y, 150, 6);
      doc.setFont("helvetica", "normal");
      doc.setFontSize(9);
      doc.text(exchange.observacoes || "", 34, y + 4.5);

      y += 25;

      // 6. RodapĂ© Legal
      doc.setFontSize(8);
      doc.setDrawColor(0, 0, 0);
      doc.line(20, y, 85, y);

      doc.setFont("helvetica", "bold");
      doc.text(exchange.colaborador_nome, 52.5, y - 1, { align: 'center' });

      doc.setFont("helvetica", "normal");
      const footerCompany = logoPref === 'cirion' ? "Cirion Technologies" : "nossa organizaĂ§ĂŁo";
      doc.text(`compromete-se a usar e devolver os equipamentos e acessĂłrios`, 87, y);
      y += 4;
      const footerText = `fornecidos pela empresa em perfeitas condiĂ§Ă”es e com todas as informaĂ§Ă”es, arquivos, contatos, arquivos de dados pessoais, e-mails, documentos de propriedades da ${footerCompany} e / ou qualquer uma das suas filiais, no tĂ©rmino do seu contrato de trabalho ou no final do perĂ­odo de autorizaĂ§ĂŁo, sem as alterar, modificar, copiar, transferir, no estado em que foram entregues e sempre observando o princĂ­pio da confidencialidade. Se compromete em notificar o responsĂĄvel de TI em caso de perda ou destruiĂ§ĂŁo do laptop, para que as medidas de seguranĂ§a necessĂĄrias para a proteĂ§ĂŁo de dados sejam aplicadas.`;
      const splitText = doc.splitTextToSize(footerText, 175);
      doc.text(splitText, 20, y);

      y += 30;

      // 7. Data e Assinaturas
      const date = new Date(exchange.data_troca + 'T12:00:00');
      const months = ["janeiro", "fevereiro", "marĂ§o", "abril", "maio", "junho", "julho", "agosto", "setembro", "outubro", "novembro", "dezembro"];
      const dateStr = `Data: ${date.getDate()} de ${months[date.getMonth()]} de ${date.getFullYear()}`;
      doc.setFontSize(10);
      doc.setFont("helvetica", "bold");
      doc.text(dateStr, 20, y);

      y += 25;
      doc.setDrawColor(0, 0, 0);
      doc.line(20, y, 75, y);
      doc.line(120, y, 185, y);

      doc.setFontSize(8);
      doc.setFont("helvetica", "normal");

      const tiLabel = logoPref === 'cirion' ? "TI - Cirion: Gilberto Araujo" : "ResponsĂĄvel TI: Gilberto Araujo";
      const colabLabel = logoPref === 'cirion' ? `Colaborador Cirion: ${exchange.colaborador_nome}` : `Colaborador: ${exchange.colaborador_nome}`;

      doc.text(tiLabel, 47.5, y + 4, { align: 'center' });
      doc.text(colabLabel, 152.5, y + 4, { align: 'center' });

      // Assinaturas Digitais
      doc.setFont("times", "italic");
      doc.setFontSize(18);
      doc.setTextColor(inkBlue);

      if (exchange.assinatura_ti) {
        doc.text(exchange.assinatura_ti, 47.5, y - 2, { align: 'center' });
      }

      if (exchange.assinatura_colaborador) {
        doc.text(exchange.assinatura_colaborador, 152.5, y - 2, { align: 'center' });
      }
    };

    renderPage(true);
    doc.addPage();
    renderPage(false);

    // Nome do arquivo conforme solicitado: apenas o nome do destinatĂĄrio
    const fileName = `${exchange.colaborador_nome.replace(/\s+/g, '_')}.pdf`;
    doc.save(fileName);
  } catch (error) {
    console.error("Erro ao gerar PDF:", error);
    alert("Erro ao processar o modelo do PDF.");
  }
};

import React, { useState } from 'react';
import { MockEmail, AssetExchange, LogoPreference } from '../types';
import { Mail, Trash2, Clock, Paperclip, PenLine, ShieldCheck, X, ChevronLeft, FileDown, CheckCircle2 } from 'lucide-react';
