  });

  const [theme, setTheme] = useState<'light' | 'dark'>(() => {
    const saved = localStorage.getItem('theme');
    return (saved === 'light' || saved === 'dark') ? saved : 'light';
  });

  const [logoPref, setLogoPref] = useState<LogoPreference>(() => {
    const saved = localStorage.getItem('logo_preference');
    return (saved === 'cirion' || saved === 'none') ? saved : 'cirion';
  });

  useEffect(() => {
    loadData();
    checkM365();
    const savedEmails = localStorage.getItem('mock_emails');
    if (savedEmails) setEmails(JSON.parse(savedEmails));
  }, []);

  const loadData = async () => {
    const data = await apiService.getAll();
    setExchanges(data);
  };

  const checkM365 = async () => {
    const account = await m365Service.getAccount();
    setM365Account(account);
  };

  const handleM365Login = async () => {
    try {
      const account = await m365Service.login();
      setM365Account(account);
      showNotification("Conectado ao Microsoft 365!");
    } catch (err) {
      setShowConfigModal(true);
    }
  };

  const handleM365Logout = async () => {
    await m365Service.logout();
    setM365Account(null);
    showNotification("Desconectado do Microsoft 365.", "error");
  };

  useEffect(() => {
    localStorage.setItem('mock_emails', JSON.stringify(emails));
  }, [emails]);

  useEffect(() => {
    localStorage.setItem('logo_preference', logoPref);
  }, [logoPref]);

  useEffect(() => {
    localStorage.setItem('sidebar_visible', JSON.stringify(isSidebarVisible));
  }, [isSidebarVisible]);

  useEffect(() => {
    localStorage.setItem('theme', theme);
    const root = window.document.documentElement;
    if (theme === 'dark') {
      root.classList.add('dark');
    } else {
      root.classList.remove('dark');
    }
  }, [theme]);

  const showNotification = (message: string, type: 'success' | 'error' = 'success') => {
    setNotification({ message, type });
    setTimeout(() => setNotification(null), 5000);
  };

  const handleSaveExchange = async (exchange: AssetExchange) => {
    setIsLoading(true);
    try {
      await apiService.save(exchange);
      await loadData();
      setEditingExchange(null);
      setCurrentView('inventory');
      showNotification("Registro gravado.");
    } catch (error) {
      showNotification("Erro ao salvar.", "error");
    } finally {
      setIsLoading(false);
    }
  };

  const handleDeleteRequest = (id: string) => {
    setItemToDelete(id);
  };

  const confirmDelete = async () => {
    if (!itemToDelete) return;
    setIsLoading(true);
    try {
      await apiService.delete(itemToDelete);
      await loadData();
      showNotification("Registro removido.", "success");
    } catch (error) {
      showNotification("Erro ao remover.", "error");
    } finally {
      setIsLoading(false);
      setItemToDelete(null);
    }
  };

  const handleSignSender = async (id: string, signature: string) => {
    const exchange = exchanges.find(e => e.id === id);
    if (!exchange) return;
    const updated: AssetExchange = { ...exchange, assinatura_ti: signature, status: 'pending_receiver' };
    await apiService.save(updated);
    await loadData();
    const newEmail: MockEmail = {
      id: Math.random().toString(36).substr(2, 9),
      exchangeId: id,
      from: 'TI Infra - AssetFlow <infra@cirion.com>',
      to: exchange.colaborador_email,
      subject: `[AĂĂO NECESSĂRIA] Termo de Troca - ${exchange.colaborador_nome}`,
      body: `OlĂĄ ${exchange.colaborador_nome},\n\nRevise e assine o termo em anexo.`,
      sentAt: new Date().toISOString(),
      read: false,
      attachment: true
    };
    setEmails([newEmail, ...emails]);
    setSigningExchange(null);
    showNotification("Termo enviado.");
  };

  const navTo = (view: View) => {
    setEditingExchange(null);
    setSigningExchange(null);
    setCurrentView(view);
  };

  return (
    <div className="flex h-screen bg-slate-50 dark:bg-dracula-bg text-slate-900 dark:text-dracula-fg overflow-hidden">

      {/* Sidebar adaptativa - Layout Original */}
      <aside className={`bg-slate-900 dark:bg-dracula-darker text-white flex-shrink-0 flex flex-col shadow-2xl transition-all duration-300 ease-in-out ${isSidebarVisible ? 'w-80' : 'w-0 opacity-0 overflow-hidden'}`}>
        <div className="p-8 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <HardDrive className="text-dracula-purple" size={24} />
            <h1 className="text-xl font-bold">AssetFlow</h1>
          </div>
          <button onClick={() => setIsSidebarVisible(false)} className="p-2 hover:bg-slate-800 rounded-lg text-slate-500">
            <PanelLeftClose size={18} />
          </button>
        </div>

        <nav className="flex-1 px-4 py-6 space-y-2 overflow-y-auto">
          <NavItem icon={PlusCircle} label="Nova Troca" active={currentView === 'form'} onClick={() => navTo('form')} />
          <NavItem icon={ClipboardList} label="InventĂĄrio" active={currentView === 'inventory'} onClick={() => navTo('inventory')} />
          <NavItem icon={Mail} label="Outlook" active={currentView === 'inbox'} onClick={() => navTo('inbox')} badge={emails.some(e => !e.read)} />
        </nav>

        <div className="p-6 border-t border-slate-800 space-y-4">
           <div className="flex items-center justify-between mb-4">
             <button onClick={() => setTheme(theme === 'light' ? 'dark' : 'light')} className="p-2 bg-slate-800 rounded-xl hover:text-dracula-purple transition-colors">
               {theme === 'light' ? <Moon size={18} /> : <Sun size={18} />}
             </button>
             <button onClick={() => setShowConfigModal(true)} className="p-2 bg-slate-800 rounded-xl hover:text-dracula-purple transition-colors">
               <Settings size={18} />
             </button>
           </div>
           <button className="w-full flex items-center gap-3 px-4 py-3 text-xs text-slate-500 hover:text-rose-400 transition-colors bg-white/5 rounded-xl">
              <LogOut size={16} /> <span>Sair do Sistema</span>
           </button>
        </div>
      </aside>

      {/* Main Area */}
      <main className="flex-1 flex flex-col min-w-0 overflow-hidden relative">

        {/* BotĂŁo de abrir sidebar quando oculta */}
        {!isSidebarVisible && (
          <button 
            onClick={() => setIsSidebarVisible(true)}
            className="absolute left-6 top-8 z-50 p-2.5 bg-slate-900 text-white rounded-xl shadow-2xl hover:scale-105 transition-all"
            title="Abrir Menu"
          >
            <Menu size={24} />
          </button>
        )}

        {notification && (
          <div className="fixed top-6 right-6 z-[100] animate-in slide-in-from-right duration-300">
            <div className={`px-6 py-4 rounded-2xl shadow-2xl border flex items-center gap-3 ${notification.type === 'success' ? 'bg-emerald-50 border-emerald-200 text-emerald-800 dark:bg-dracula-green/20 dark:text-dracula-green' : 'bg-rose-50 border-rose-200 text-rose-800 dark:bg-dracula-red/20 dark:text-dracula-red'}`}>
              {notification.type === 'success' ? <CheckCircle2 size={20} /> : <AlertCircle size={20} />}
              <span className="font-bold text-sm">{notification.message}</span>
            </div>
          </div>
        )}

        <div className="flex-1 overflow-y-auto p-4 md:p-10 space-y-8 transition-all duration-300">
          <header className="space-y-1">
            <h2 className="text-3xl font-extrabold tracking-tight">
              {currentView === 'form' ? 'GestĂŁo de Ativos' : currentView === 'inventory' ? 'InventĂĄrio' : 'Outlook'}
            </h2>
            <p className="text-slate-500 text-sm font-medium">Controle de equipamentos TI Cirion</p>
          </header>

          <div className="bg-white dark:bg-dracula-darker rounded-[2.5rem] shadow-2xl border border-slate-100 dark:border-dracula-current min-h-[600px] overflow-hidden">
            {currentView === 'form' && (
              <AssetForm 
                onSave={handleSaveExchange} 
                editingExchange={editingExchange} 
                onCancel={() => navTo('inventory')} 
                m365Connected={!!m365Account}
              />
            )}
            {currentView === 'inventory' && (
              <InventoryTable 
                exchanges={exchanges} 
                onDelete={handleDeleteRequest} 
                onEdit={(ex) => { setEditingExchange(ex); setCurrentView('form'); }} 
                onNotify={showNotification}
                onSignStart={setSigningExchange}
                onBulkImport={(data) => { exchanges.push(...data); loadData(); }}
                logoPref={logoPref}
              />
            )}
            {currentView === 'inbox' && (
              <MockInbox 
                emails={emails} 
                onUpdateEmails={setEmails} 
                exchanges={exchanges}
                onSignReceiver={(id, sig) => {
                  const ex = exchanges.find(e => e.id === id);
                  if(ex) { ex.status = 'completed'; ex.assinatura_colaborador = sig; apiService.save(ex); loadData(); showNotification("Termo finalizado!"); }
                }}
                logoPref={logoPref}
              />
            )}
          </div>
        </div>
      </main>

      {signingExchange && <SenderSignatureModal exchange={signingExchange} onClose={() => setSigningExchange(null)} onConfirm={handleSignSender} />}

      {itemToDelete && (
        <ConfirmationModal 
          title="Excluir Registro" 
          message="Tem certeza que deseja excluir este item permanentemente? Esta aĂ§ĂŁo nĂŁo pode ser desfeita."
          onConfirm={confirmDelete}
          onCancel={() => setItemToDelete(null)}
          isDanger
          confirmLabel="Excluir"
          confirmationKeyword="excluiragora"
        />
      )}

      {showConfigModal && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-4 bg-slate-900/90 backdrop-blur-md">
           <div className="bg-white dark:bg-dracula-bg w-full max-w-sm rounded-[2rem] p-8 border shadow-2xl">
              <h3 className="text-xl font-bold mb-6">Configurar Microsoft 365</h3>
              <div className="space-y-4">
                 <input id="cfg_cid" placeholder="Application Client ID" className="w-full p-4 rounded-xl border dark:bg-dracula-darker text-xs font-mono"/>
                 <input id="cfg_tid" placeholder="Directory Tenant ID" className="w-full p-4 rounded-xl border dark:bg-dracula-darker text-xs font-mono"/>
                 <div className="flex gap-3 pt-4">
                    <button onClick={() => setShowConfigModal(false)} className="flex-1 py-3 text-slate-400 font-bold">Cancelar</button>
                    <button onClick={() => {
                       const c = (document.getElementById('cfg_cid') as HTMLInputElement).value;
                       const t = (document.getElementById('cfg_tid') as HTMLInputElement).value;
                       if(c && t) { m365Service.updateConfig(c, t); setShowConfigModal(false); showNotification("Salvo!"); }
                    }} className="flex-1 py-3 bg-dracula-purple text-white rounded-xl font-bold transition-transform active:scale-95">Salvar</button>
                 </div>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

const NavItem = ({ icon: Icon, label, active, onClick, badge }: any) => (
  <button
    onClick={onClick}
    className={`w-full flex items-center gap-4 px-4 py-4 rounded-xl transition-all relative ${active ? 'bg-dracula-purple text-white shadow-xl shadow-dracula-purple/20' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}
  >
    <Icon size={20} />
    <span className="font-bold text-sm">{label}</span>
    {badge && <div className="absolute right-4 w-2 h-2 bg-dracula-pink rounded-full" />}
  </button>
);

export default App;

import React, { useState } from 'react';
import { AlertTriangle, Lock } from 'lucide-react';

interface ConfirmationModalProps {
  title: string;
  message: string;
  onConfirm: () => void;
  onCancel: () => void;
  confirmLabel?: string;
  isDanger?: boolean;
  confirmationKeyword?: string;
}

const ConfirmationModal: React.FC<ConfirmationModalProps> = ({ 
  title, message, onConfirm, onCancel, confirmLabel = "Confirmar", isDanger = false, confirmationKeyword
}) => {
  const [inputValue, setInputValue] = useState('');
  const isConfirmDisabled = confirmationKeyword ? inputValue !== confirmationKeyword : false;

  return (
    <div className="fixed inset-0 z-[200] flex items-center justify-center p-4 bg-slate-900/80 backdrop-blur-sm animate-in fade-in duration-200">
      <div className="bg-white dark:bg-dracula-bg w-full max-w-sm rounded-3xl p-6 shadow-2xl border border-white/10">
        <div className="flex flex-col items-center text-center gap-4">
          <div className={`p-4 rounded-full ${isDanger ? 'bg-rose-100 text-rose-600 dark:bg-rose-900/30 dark:text-rose-400' : 'bg-blue-100 text-blue-600'}`}>
            <AlertTriangle size={32} />
          </div>
          <div>
            <h3 className="text-xl font-bold mb-2 text-slate-900 dark:text-white">{title}</h3>
            <p className="text-slate-500 dark:text-slate-400 text-sm leading-relaxed">{message}</p>
          </div>

          {confirmationKeyword && (
            <div className="w-full text-left space-y-2 mt-2">
              <label className="text-xs font-bold text-slate-400 uppercase flex items-center gap-1">
                <Lock size={12} /> Senha de SeguranĂ§a
              </label>
              <input 
                type="password"
                placeholder="Digite a senha..."
                className="w-full p-3 rounded-xl border-2 border-slate-200 dark:border-dracula-current bg-slate-50 dark:bg-dracula-darker text-center font-bold text-slate-700 dark:text-white outline-none focus:border-rose-400 transition-all"
                value={inputValue}
                onChange={(e) => setInputValue(e.target.value)}
                autoFocus
              />
            </div>
          )}

          <div className="flex gap-3 w-full mt-4">
            <button 
              onClick={onCancel}
              className="flex-1 py-3 bg-slate-100 dark:bg-slate-800 text-slate-700 dark:text-slate-300 rounded-xl font-bold hover:bg-slate-200 dark:hover:bg-slate-700 transition-colors"
            >
              Cancelar
            </button>
            <button 
              onClick={onConfirm}
              disabled={isConfirmDisabled}
              className={`flex-1 py-3 text-white rounded-xl font-bold transition-all active:scale-95 shadow-lg disabled:opacity-50 disabled:cursor-not-allowed disabled:active:scale-100 ${isDanger ? 'bg-rose-500 hover:bg-rose-600 shadow-rose-500/30' : 'bg-blue-600 hover:bg-blue-700'}`}
            >
              {confirmLabel}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default ConfirmationModal;

import { jsPDF } from 'jspdf';
import { AssetExchange, LogoPreference } from '../types';

export const generateAssetPDF = (exchange: AssetExchange, logoPref: LogoPreference = 'cirion') => {
  try {
    const doc = new jsPDF({
      orientation: 'p',
      unit: 'mm',
      format: 'a4'
    });

    // Cores extraĂ­das para o efeito 3D e visual
    const cirionBlue = "#1a5edb"; 
    const cirionShadow = "#0a3a8a"; 
    const boxBlue = "#00158a"; 
    const inkBlue = "#003087";

    const renderPage = (isEntregue: boolean) => {
      const prefix = isEntregue ? 'entregue_' : 'devolvido_';

      // 1. RenderizaĂ§ĂŁo condicional do logotipo
      if (logoPref === 'cirion') {
        const startX = 25;
        const startY = 25;
        const mainText = "CIRION";
        const subText = "TECHNOLOGIES";

        // Parte Principal
        doc.setFont("helvetica", "bold");
        doc.setFontSize(28);
        doc.setTextColor(cirionShadow);
        doc.text(mainText, startX + 0.4, startY + 0.4);
        doc.setTextColor(cirionBlue);
        doc.text(mainText, startX, startY);

        // Subtexto
        doc.setFontSize(9);
        doc.setCharSpace(1.5);
        doc.setTextColor(cirionShadow);
        doc.text(subText, startX + 0.8, startY + 7.3);
        doc.setTextColor(cirionBlue);
        doc.text(subText, startX + 0.5, startY + 7);
        doc.setCharSpace(0);
      }

      // TĂ­tulo e Checkboxes
      doc.setFontSize(11);
      doc.setTextColor(boxBlue);
      const titleText = logoPref === 'cirion' ? "DeclaraĂ§ĂŁo de Equipamento Cirion" : "DeclaraĂ§ĂŁo de Entrega de Equipamento";
      doc.text(titleText, 85, 20);

      doc.setDrawColor(boxBlue);
      doc.setLineWidth(0.3);

      // Checkbox Entrega
      doc.rect(85, 23, 3, 3);
      if (isEntregue) doc.text("x", 86, 25.5);
      doc.setFontSize(9);
      doc.text("Entrega", 90, 25.5);

      // Checkbox DevoluĂ§ĂŁo
      doc.rect(110, 23, 3, 3);
      if (!isEntregue) doc.text("x", 111, 25.5);
      doc.text("DevoluĂ§ĂŁo", 115, 25.5);

      // 2. Texto de IntroduĂ§ĂŁo
      doc.setFontSize(9);
      doc.setTextColor(0, 0, 0);
      doc.setFont("helvetica", "normal");
      doc.text("Eu, ", 20, 40);
      doc.line(26, 40.5, 95, 40.5);
      doc.setFont("helvetica", "bold");
      doc.text(exchange.colaborador_nome, 28, 40);
      doc.setFont("helvetica", "normal");
      doc.text("declaro ter recebido/devolvido o", 97, 40);
      doc.text("equipamento e acessĂłrios abaixo descritos, em perfeitas condiĂ§Ă”es de funcionamento.", 20, 45);

      // 3. Campos de Dados
      let y = 55;
      const LABEL_X = 20;
      const FIELD_X = 40;
      const BOX_WIDTH = 100;

      const drawField = (label: string, value: string, width: number = BOX_WIDTH, customX: number = FIELD_X) => {
        doc.setFont("helvetica", "bold");
        doc.setFontSize(11);
        doc.setTextColor(0, 0, 0);
        doc.text(label, LABEL_X, y + 4.5);

        doc.setDrawColor(boxBlue);
        doc.rect(customX, y, width, 6);
        doc.setFont("helvetica", "normal");
        doc.text(value || "", customX + 2, y + 4.5);
        y += 8;
      };

      drawField("Tipo:", String(exchange[`${prefix}tipo` as keyof AssetExchange]));
      drawField("Marca:", String(exchange[`${prefix}marca` as keyof AssetExchange]));
      drawField("Modelo:", String(exchange[`${prefix}modelo` as keyof AssetExchange]));
      drawField("NĂșmero de Serie / Imei:", String(exchange[`${prefix}serial` as keyof AssetExchange]), 82, 68);
      drawField("Estado:", String(exchange[`${prefix}condicao` as keyof AssetExchange]), 25);

      y += 2;
      doc.setFont("helvetica", "bold");
      doc.text("Tamanho do HD:", 20, y + 4.5);
      doc.rect(58, y, 30, 6);
      doc.setFont("helvetica", "normal");
      doc.text(String(exchange[`${prefix}armazenamento` as keyof AssetExchange]), 60, y + 4.5);
      y += 8;

      drawField("Processador:", String(exchange[`${prefix}processador` as keyof AssetExchange]), 150, 50);

      doc.setFont("helvetica", "bold");
      doc.text("MemĂłria:", 20, y + 4.5);
      doc.rect(42, y, 25, 6);
      doc.setFont("helvetica", "normal");
      doc.text(String(exchange[`${prefix}memoria` as keyof AssetExchange]), 44, y + 4.5);
      y += 15;

      // 4. Caixa de AcessĂłrios
      doc.setFontSize(12);
      doc.setFont("helvetica", "bold");
      doc.text("AcessĂłrios:", 105, y, { align: "center" });
      y += 4;

      doc.setDrawColor(boxBlue);
      doc.rect(45, y, 120, 20);

      const accessories = ["Mouse", "Teclado", "Headset", "Mochila", "DockStation", "Monitor"];
      const selectedAccs = (exchange[`${prefix}acessorios` as keyof AssetExchange] as string[]) || [];

      doc.setFontSize(10);
      doc.setFont("helvetica", "normal");
      let accX = 65;
      let accY = y + 5;

      accessories.forEach((acc, index) => {
        doc.rect(accX, accY - 2.5, 3, 3);
        if (selectedAccs.includes(acc)) doc.text("x", accX + 0.8, accY);
        doc.text(acc, accX + 5, accY);

        if (index === 2) {
          accX = 110;
          accY = y + 5;
        } else {
          accY += 6;
        }
      });

      y += 35;

      // 5. ObservaĂ§Ă”es
      doc.setFontSize(11);
      doc.setFont("helvetica", "bold");
      doc.text("Obs:", 20, y + 4.5);
      doc.rect(32, y, 150, 6);

      // ObtĂ©m o texto especĂ­fico para a pĂĄgina atual (Entrega ou DevoluĂ§ĂŁo)
      let obsText = "";
      if (isEntregue) {
        obsText = exchange.entregue_observacoes || "";
      } else {
        obsText = exchange.devolvido_observacoes || "";
      }

      // Fallback para campo antigo se os novos estiverem vazios (retrocompatibilidade)
      if (!obsText && (exchange as any).observacoes) {
        obsText = (exchange as any).observacoes;
      }

      doc.setFont("helvetica", "normal");
      doc.setFontSize(9);
      doc.text(obsText || "", 34, y + 4.5, { maxWidth: 145 });

      y += 25;

      // 6. RodapĂ© Legal
      doc.setFontSize(8);
      doc.setDrawColor(0, 0, 0);
      doc.line(20, y, 85, y);

      doc.setFont("helvetica", "bold");
      doc.text(exchange.colaborador_nome, 52.5, y - 1, { align: 'center' });

      doc.setFont("helvetica", "normal");
      const footerCompany = logoPref === 'cirion' ? "Cirion Technologies" : "nossa organizaĂ§ĂŁo";
      doc.text(`compromete-se a usar e devolver os equipamentos e acessĂłrios`, 87, y);
      y += 4;
      const footerText = `fornecidos pela empresa em perfeitas condiĂ§Ă”es e com todas as informaĂ§Ă”es, arquivos, contatos, arquivos de dados pessoais, e-mails, documentos de propriedades da ${footerCompany} e / ou qualquer uma das suas filiais, no tĂ©rmino do seu contrato de trabalho ou no final do perĂ­odo de autorizaĂ§ĂŁo, sem as alterar, modificar, copiar, transferir, no estado em que foram entregues e sempre observando o princĂ­pio da confidencialidade. Se compromete em notificar o responsĂĄvel de TI em caso de perda ou destruiĂ§ĂŁo do laptop, para que as medidas de seguranĂ§a necessĂĄrias para a proteĂ§ĂŁo de dados sejam aplicadas.`;
      const splitText = doc.splitTextToSize(footerText, 175);
      doc.text(splitText, 20, y);

      y += 30;

      // 7. Data e Assinaturas
      const date = new Date(exchange.data_troca + 'T12:00:00');
      const months = ["janeiro", "fevereiro", "marĂ§o", "abril", "maio", "junho", "julho", "agosto", "setembro", "outubro", "novembro", "dezembro"];
      const dateStr = `Data: ${date.getDate()} de ${months[date.getMonth()]} de ${date.getFullYear()}`;
      doc.setFontSize(10);
      doc.setFont("helvetica", "bold");
      doc.text(dateStr, 20, y);

      y += 25;
      doc.setDrawColor(0, 0, 0);
      doc.line(20, y, 75, y);
      doc.line(120, y, 185, y);

      doc.setFontSize(8);
      doc.setFont("helvetica", "normal");

      const tiLabel = logoPref === 'cirion' ? "TI - Cirion: Gilberto Araujo" : "ResponsĂĄvel TI: Gilberto Araujo";
      const colabLabel = logoPref === 'cirion' ? `Colaborador Cirion: ${exchange.colaborador_nome}` : `Colaborador: ${exchange.colaborador_nome}`;

      doc.text(tiLabel, 47.5, y + 4, { align: 'center' });
      doc.text(colabLabel, 152.5, y + 4, { align: 'center' });

      // Assinaturas Digitais
      doc.setFont("times", "italic");
      doc.setFontSize(18);
      doc.setTextColor(inkBlue);

      if (exchange.assinatura_ti) {
        doc.text(exchange.assinatura_ti, 47.5, y - 2, { align: 'center' });
      }

      if (exchange.assinatura_colaborador) {
        doc.text(exchange.assinatura_colaborador, 152.5, y - 2, { align: 'center' });
      }
    };

    renderPage(true);
    doc.addPage();
    renderPage(false);

    // ConstrĂłi nome do arquivo: NOME + TIPO + SERIAIS + DATA + SUFIXO
    const clean = (str: string) => str ? str.replace(/[^a-zA-Z0-9\s-]/g, '').trim().toUpperCase() : 'NA';

    const nome = clean(exchange.colaborador_nome);
    const tipo = clean(exchange.entregue_tipo || exchange.devolvido_tipo || "Equipamento");
    const serialEnt = clean(exchange.entregue_serial);
    const serialDev = clean(exchange.devolvido_serial);
    const data = exchange.data_troca;

    const fileName = `${nome} ${tipo} ${serialEnt} ${serialDev} ${data} ENTREGA E DEVOLUCAO.pdf`;
    doc.save(fileName);
  } catch (error) {
    console.error("Erro ao gerar PDF:", error);
    alert("Erro ao processar o modelo do PDF.");
  }
};

import { jsPDF } from 'jspdf';
import { AssetExchange, LogoPreference } from '../types';

export const generateAssetPDF = (exchange: AssetExchange, logoPref: LogoPreference = 'cirion') => {
  try {
    const doc = new jsPDF({
      orientation: 'p',
      unit: 'mm',
      format: 'a4'
    });

    // Cores extraĂ­das para o efeito 3D e visual
    const cirionBlue = "#1a5edb"; 
    const cirionShadow = "#0a3a8a"; 
    const boxBlue = "#00158a"; 
    const inkBlue = "#003087";

    const renderPage = (isEntregue: boolean) => {
      const prefix = isEntregue ? 'entregue_' : 'devolvido_';

      // 1. RenderizaĂ§ĂŁo condicional do logotipo
      if (logoPref === 'cirion') {
        const startX = 25;
        const startY = 25;
        const mainText = "CIRION";
        const subText = "TECHNOLOGIES";

        // Parte Principal
        doc.setFont("helvetica", "bold");
        doc.setFontSize(28);
        doc.setTextColor(cirionShadow);
        doc.text(mainText, startX + 0.4, startY + 0.4);
        doc.setTextColor(cirionBlue);
        doc.text(mainText, startX, startY);

        // Subtexto
        doc.setFontSize(9);
        doc.setCharSpace(1.5);
        doc.setTextColor(cirionShadow);
        doc.text(subText, startX + 0.8, startY + 7.3);
        doc.setTextColor(cirionBlue);
        doc.text(subText, startX + 0.5, startY + 7);
        doc.setCharSpace(0);
      }

      // TĂ­tulo e Checkboxes
      doc.setFontSize(11);
      doc.setTextColor(boxBlue);
      const titleText = logoPref === 'cirion' ? "DeclaraĂ§ĂŁo de Equipamento Cirion" : "DeclaraĂ§ĂŁo de Entrega de Equipamento";
      doc.text(titleText, 85, 20);

      doc.setDrawColor(boxBlue);
      doc.setLineWidth(0.3);

      // Checkbox Entrega
      doc.rect(85, 23, 3, 3);
      if (isEntregue) doc.text("x", 86, 25.5);
      doc.setFontSize(9);
      doc.text("Entrega", 90, 25.5);

      // Checkbox DevoluĂ§ĂŁo
      doc.rect(110, 23, 3, 3);
      if (!isEntregue) doc.text("x", 111, 25.5);
      doc.text("DevoluĂ§ĂŁo", 115, 25.5);

      // 2. Texto de IntroduĂ§ĂŁo
      doc.setFontSize(9);
      doc.setTextColor(0, 0, 0);
      doc.setFont("helvetica", "normal");
      doc.text("Eu, ", 20, 40);
      doc.line(26, 40.5, 95, 40.5);
      doc.setFont("helvetica", "bold");
      doc.text(exchange.colaborador_nome, 28, 40);
      doc.setFont("helvetica", "normal");
      doc.text("declaro ter recebido/devolvido o", 97, 40);
      doc.text("equipamento e acessĂłrios abaixo descritos, em perfeitas condiĂ§Ă”es de funcionamento.", 20, 45);

      // 3. Campos de Dados
      let y = 55;
      const LABEL_X = 20;
      const FIELD_X = 40;
      const BOX_WIDTH = 100;

      const drawField = (label: string, value: string, width: number = BOX_WIDTH, customX: number = FIELD_X) => {
        doc.setFont("helvetica", "bold");
        doc.setFontSize(11);
        doc.setTextColor(0, 0, 0);
        doc.text(label, LABEL_X, y + 4.5);

        doc.setDrawColor(boxBlue);
        doc.rect(customX, y, width, 6);
        doc.setFont("helvetica", "normal");
        doc.text(value || "", customX + 2, y + 4.5);
        y += 8;
      };

      drawField("Tipo:", String(exchange[`${prefix}tipo` as keyof AssetExchange]));
      drawField("Marca:", String(exchange[`${prefix}marca` as keyof AssetExchange]));
      drawField("Modelo:", String(exchange[`${prefix}modelo` as keyof AssetExchange]));
      drawField("NĂșmero de Serie / Imei:", String(exchange[`${prefix}serial` as keyof AssetExchange]), 82, 68);
      drawField("Estado:", String(exchange[`${prefix}condicao` as keyof AssetExchange]), 25);

      y += 2;
      doc.setFont("helvetica", "bold");
      doc.text("Tamanho do HD:", 20, y + 4.5);
      doc.rect(58, y, 30, 6);
      doc.setFont("helvetica", "normal");
      doc.text(String(exchange[`${prefix}armazenamento` as keyof AssetExchange]), 60, y + 4.5);
      y += 8;

      drawField("Processador:", String(exchange[`${prefix}processador` as keyof AssetExchange]), 150, 50);

      doc.setFont("helvetica", "bold");
      doc.text("MemĂłria:", 20, y + 4.5);
      doc.rect(42, y, 25, 6);
      doc.setFont("helvetica", "normal");
      doc.text(String(exchange[`${prefix}memoria` as keyof AssetExchange]), 44, y + 4.5);
      y += 15;

      // 4. Caixa de AcessĂłrios
      doc.setFontSize(12);
      doc.setFont("helvetica", "bold");
      doc.text("AcessĂłrios:", 105, y, { align: "center" });
      y += 4;

      doc.setDrawColor(boxBlue);
      doc.rect(45, y, 120, 20);

      const accessories = ["Mouse", "Teclado", "Headset", "Mochila", "DockStation", "Monitor"];
      const selectedAccs = (exchange[`${prefix}acessorios` as keyof AssetExchange] as string[]) || [];

      doc.setFontSize(10);
      doc.setFont("helvetica", "normal");
      let accX = 65;
      let accY = y + 5;

      accessories.forEach((acc, index) => {
        doc.rect(accX, accY - 2.5, 3, 3);
        if (selectedAccs.includes(acc)) doc.text("x", accX + 0.8, accY);
        doc.text(acc, accX + 5, accY);

        if (index === 2) {
          accX = 110;
          accY = y + 5;
        } else {
          accY += 6;
        }
      });

      y += 35;

      // 5. ObservaĂ§Ă”es
      doc.setFontSize(11);
      doc.setFont("helvetica", "bold");
      doc.text("Obs:", 20, y + 4.5);
      doc.rect(32, y, 150, 6);

      // ObtĂ©m o texto especĂ­fico para a pĂĄgina atual (Entrega ou DevoluĂ§ĂŁo)
      let obsText = "";
      if (isEntregue) {
        obsText = exchange.entregue_observacoes || "";
      } else {
        obsText = exchange.devolvido_observacoes || "";
      }

      // Fallback para campo antigo se os novos estiverem vazios (retrocompatibilidade)
      if (!obsText && (exchange as any).observacoes) {
        obsText = (exchange as any).observacoes;
      }

      doc.setFont("helvetica", "normal");
      doc.setFontSize(9);
      doc.text(obsText || "", 34, y + 4.5, { maxWidth: 145 });

      y += 25;

      // 6. RodapĂ© Legal
      doc.setFontSize(8);
      doc.setDrawColor(0, 0, 0);
      doc.line(20, y, 85, y);

      doc.setFont("helvetica", "bold");
      doc.text(exchange.colaborador_nome, 52.5, y - 1, { align: 'center' });

      doc.setFont("helvetica", "normal");
      const footerCompany = logoPref === 'cirion' ? "Cirion Technologies" : "nossa organizaĂ§ĂŁo";
      doc.text(`compromete-se a usar e devolver os equipamentos e acessĂłrios`, 87, y);
      y += 4;
      const footerText = `fornecidos pela empresa em perfeitas condiĂ§Ă”es e com todas as informaĂ§Ă”es, arquivos, contatos, arquivos de dados pessoais, e-mails, documentos de propriedades da ${footerCompany} e / ou qualquer uma das suas filiais, no tĂ©rmino do seu contrato de trabalho ou no final do perĂ­odo de autorizaĂ§ĂŁo, sem as alterar, modificar, copiar, transferir, no estado em que foram entregues e sempre observando o princĂ­pio da confidencialidade. Se compromete em notificar o responsĂĄvel de TI em caso de perda ou destruiĂ§ĂŁo do laptop, para que as medidas de seguranĂ§a necessĂĄrias para a proteĂ§ĂŁo de dados sejam aplicadas.`;
      const splitText = doc.splitTextToSize(footerText, 175);
      doc.text(splitText, 20, y);

      y += 30;

      // 7. Data e Assinaturas
      const date = new Date(exchange.data_troca + 'T12:00:00');
      const months = ["janeiro", "fevereiro", "marĂ§o", "abril", "maio", "junho", "julho", "agosto", "setembro", "outubro", "novembro", "dezembro"];
      const dateStr = `Data: ${date.getDate()} de ${months[date.getMonth()]} de ${date.getFullYear()}`;
      doc.setFontSize(10);
      doc.setFont("helvetica", "bold");
      doc.text(dateStr, 20, y);

      y += 25;
      doc.setDrawColor(0, 0, 0);
      doc.line(20, y, 75, y);
      doc.line(120, y, 185, y);

      doc.setFontSize(8);
      doc.setFont("helvetica", "normal");

      const tiLabel = logoPref === 'cirion' ? "TI - Cirion: Gilberto Araujo" : "ResponsĂĄvel TI: Gilberto Araujo";
      const colabLabel = logoPref === 'cirion' ? `Colaborador Cirion: ${exchange.colaborador_nome}` : `Colaborador: ${exchange.colaborador_nome}`;

      doc.text(tiLabel, 47.5, y + 4, { align: 'center' });
      doc.text(colabLabel, 152.5, y + 4, { align: 'center' });

      // Assinaturas Digitais
      doc.setFont("times", "italic");
      doc.setFontSize(18);
      doc.setTextColor(inkBlue);

      if (exchange.assinatura_ti) {
        doc.text(exchange.assinatura_ti, 47.5, y - 2, { align: 'center' });
      }

      if (exchange.assinatura_colaborador) {
        doc.text(exchange.assinatura_colaborador, 152.5, y - 2, { align: 'center' });
      }
    };

    renderPage(true);
    doc.addPage();
    renderPage(false);

    // ConstrĂłi nome do arquivo: NOME + TIPO + SERIAIS + DATA + SUFIXO
    // Normaliza acentos (ex: JoĂŁo -> Joao) e remove caracteres especiais
    const clean = (str: string) => str ? str.normalize("NFD").replace(/[\u0300-\u036f]/g, "").replace(/[^a-zA-Z0-9\s-]/g, '').trim().toUpperCase() : 'NA';

    const nome = clean(exchange.colaborador_nome);
    const tipo = clean(exchange.entregue_tipo || exchange.devolvido_tipo || "Equipamento");
    const serialEnt = clean(exchange.entregue_serial);
    const serialDev = clean(exchange.devolvido_serial);
    const data = exchange.data_troca;

    const fileName = `${nome} ${tipo} ${serialEnt} ${serialDev} ${data} ENTREGA E DEVOLUCAO.pdf`;
    doc.save(fileName);
  } catch (error) {
    console.error("Erro ao gerar PDF:", error);
    alert("Erro ao processar o modelo do PDF.");
  }
};

import React, { useState, useEffect } from 'react';
import { PlusCircle, ClipboardList, LogOut, CheckCircle2, AlertCircle, Mail, Loader2, HardDrive, PanelLeftClose, Menu, Image as ImageIcon, Sun, Moon, Settings, ShieldCheck, Maximize, Minimize } from 'lucide-react';
import { View, AssetExchange, MockEmail, LogoPreference } from './types';
import AssetForm from './components/AssetForm';
import InventoryTable from './components/InventoryTable';
import MockInbox from './components/MockInbox';
import SenderSignatureModal from './components/SenderSignatureModal';
import ConfirmationModal from './components/ConfirmationModal';
import { apiService } from './services/apiService';
import { m365Service } from './services/m365Service';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>('form');
  const [exchanges, setExchanges] = useState<AssetExchange[]>([]);
  const [emails, setEmails] = useState<MockEmail[]>([]);
  const [editingExchange, setEditingExchange] = useState<AssetExchange | null>(null);
  const [signingExchange, setSigningExchange] = useState<AssetExchange | null>(null);
  const [itemToDelete, setItemToDelete] = useState<string | null>(null);
  const [notification, setNotification] = useState<{message: string, type: 'success' | 'error'} | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [m365Account, setM365Account] = useState<any>(null);
  const [showConfigModal, setShowConfigModal] = useState(false);
  const [isFullscreen, setIsFullscreen] = useState(false);

  const [isSidebarVisible, setIsSidebarVisible] = useState(() => {
    const saved = localStorage.getItem('sidebar_visible');
    return saved !== null ? JSON.parse(saved) : true;
  });

  const [theme, setTheme] = useState<'light' | 'dark'>(() => {
    const saved = localStorage.getItem('theme');
    return (saved === 'light' || saved === 'dark') ? saved : 'light';
  });

  const [logoPref, setLogoPref] = useState<LogoPreference>(() => {
    const saved = localStorage.getItem('logo_preference');
    return (saved === 'cirion' || saved === 'none') ? saved : 'cirion';
  });

  useEffect(() => {
    loadData();
    checkM365();
    const savedEmails = localStorage.getItem('mock_emails');
    if (savedEmails) setEmails(JSON.parse(savedEmails));

    // Listener para detectar saĂ­da do fullscreen via ESC
    const handleFullscreenChange = () => {
      setIsFullscreen(!!document.fullscreenElement);
    };
    document.addEventListener('fullscreenchange', handleFullscreenChange);
    return () => document.removeEventListener('fullscreenchange', handleFullscreenChange);
  }, []);

  const loadData = async () => {
    const data = await apiService.getAll();
    setExchanges(data);
  };

  const checkM365 = async () => {
    const account = await m365Service.getAccount();
    setM365Account(account);
  };

  const handleM365Login = async () => {
    try {
      const account = await m365Service.login();
      setM365Account(account);
      showNotification("Conectado ao Microsoft 365!");
    } catch (err) {
      setShowConfigModal(true);
    }
  };

  const handleM365Logout = async () => {
    await m365Service.logout();
    setM365Account(null);
    showNotification("Desconectado do Microsoft 365.", "error");
  };

  const toggleFullscreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch((err) => {
        console.error(`Erro ao tentar ativar tela cheia: ${err.message}`);
      });
    } else {
      if (document.exitFullscreen) {
        document.exitFullscreen();
      }
    }
  };

  useEffect(() => {
    localStorage.setItem('mock_emails', JSON.stringify(emails));
  }, [emails]);

  useEffect(() => {
    localStorage.setItem('logo_preference', logoPref);
  }, [logoPref]);

  useEffect(() => {
    localStorage.setItem('sidebar_visible', JSON.stringify(isSidebarVisible));
  }, [isSidebarVisible]);

  useEffect(() => {
    localStorage.setItem('theme', theme);
    const root = window.document.documentElement;
    if (theme === 'dark') {
      root.classList.add('dark');
    } else {
      root.classList.remove('dark');
    }
  }, [theme]);

  const showNotification = (message: string, type: 'success' | 'error' = 'success') => {
    setNotification({ message, type });
    setTimeout(() => setNotification(null), 5000);
  };

  const handleSaveExchange = async (exchange: AssetExchange) => {
    setIsLoading(true);
    try {
      await apiService.save(exchange);
      await loadData();
      setEditingExchange(null);
      setCurrentView('inventory');
      showNotification("Registro gravado.");
    } catch (error) {
      showNotification("Erro ao salvar.", "error");
    } finally {
      setIsLoading(false);
    }
  };

  const handleDeleteRequest = (id: string) => {
    setItemToDelete(id);
  };

  const confirmDelete = async () => {
    if (!itemToDelete) return;
    setIsLoading(true);
    try {
      await apiService.delete(itemToDelete);
      await loadData();
      showNotification("Registro removido.", "success");
    } catch (error) {
      showNotification("Erro ao remover.", "error");
    } finally {
      setIsLoading(false);
      setItemToDelete(null);
    }
  };

  const handleSignSender = async (id: string, signature: string) => {
    const exchange = exchanges.find(e => e.id === id);
    if (!exchange) return;
    const updated: AssetExchange = { ...exchange, assinatura_ti: signature, status: 'pending_receiver' };
    await apiService.save(updated);
    await loadData();
    const newEmail: MockEmail = {
      id: Math.random().toString(36).substr(2, 9),
      exchangeId: id,
      from: 'TI Infra - AssetFlow <infra@cirion.com>',
      to: exchange.colaborador_email,
      subject: `[AĂĂO NECESSĂRIA] Termo de Troca - ${exchange.colaborador_nome}`,
      body: `OlĂĄ ${exchange.colaborador_nome},\n\nRevise e assine o termo em anexo.`,
      sentAt: new Date().toISOString(),
      read: false,
      attachment: true
    };
    setEmails([newEmail, ...emails]);
    setSigningExchange(null);
    showNotification("Termo enviado.");
  };

  const navTo = (view: View) => {
    setEditingExchange(null);
    setSigningExchange(null);
    setCurrentView(view);
  };

  return (
    <div className="flex h-screen bg-slate-50 dark:bg-dracula-bg text-slate-900 dark:text-dracula-fg overflow-hidden">

      {/* Sidebar adaptativa - Layout Original */}
      <aside className={`bg-slate-900 dark:bg-dracula-darker text-white flex-shrink-0 flex flex-col shadow-2xl transition-all duration-300 ease-in-out ${isSidebarVisible ? 'w-80' : 'w-0 opacity-0 overflow-hidden'}`}>
        <div className="p-8 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <HardDrive className="text-dracula-purple" size={24} />
            <h1 className="text-xl font-bold">AssetFlow</h1>
          </div>
          <button onClick={() => setIsSidebarVisible(false)} className="p-2 hover:bg-slate-800 rounded-lg text-slate-500">
            <PanelLeftClose size={18} />
          </button>
        </div>

        <nav className="flex-1 px-4 py-6 space-y-2 overflow-y-auto">
          <NavItem icon={PlusCircle} label="Nova Troca" active={currentView === 'form'} onClick={() => navTo('form')} />
          <NavItem icon={ClipboardList} label="InventĂĄrio" active={currentView === 'inventory'} onClick={() => navTo('inventory')} />
          <NavItem icon={Mail} label="Outlook" active={currentView === 'inbox'} onClick={() => navTo('inbox')} badge={emails.some(e => !e.read)} />
        </nav>

        <div className="p-6 border-t border-slate-800 space-y-4">
           <div className="flex items-center gap-2 mb-4">
             <button 
               onClick={() => setTheme(theme === 'light' ? 'dark' : 'light')} 
               className="flex-1 flex justify-center p-2 bg-slate-800 rounded-xl hover:text-dracula-purple transition-colors"
               title="Alternar Tema"
             >
               {theme === 'light' ? <Moon size={18} /> : <Sun size={18} />}
             </button>
             <button 
               onClick={toggleFullscreen} 
               className="flex-1 flex justify-center p-2 bg-slate-800 rounded-xl hover:text-dracula-purple transition-colors"
               title="Tela Cheia"
             >
               {isFullscreen ? <Minimize size={18} /> : <Maximize size={18} />}
             </button>
             <button 
               onClick={() => setShowConfigModal(true)} 
               className="flex-1 flex justify-center p-2 bg-slate-800 rounded-xl hover:text-dracula-purple transition-colors"
               title="ConfiguraĂ§Ă”es"
             >
               <Settings size={18} />
             </button>
           </div>
           <button className="w-full flex items-center gap-3 px-4 py-3 text-xs text-slate-500 hover:text-rose-400 transition-colors bg-white/5 rounded-xl">
              <LogOut size={16} /> <span>Sair do Sistema</span>
           </button>
        </div>
      </aside>

      {/* Main Area */}
      <main className="flex-1 flex flex-col min-w-0 overflow-hidden relative">

        {/* BotĂŁo de abrir sidebar quando oculta */}
        {!isSidebarVisible && (
          <button 
            onClick={() => setIsSidebarVisible(true)}
            className="absolute left-6 top-8 z-50 p-2.5 bg-slate-900 text-white rounded-xl shadow-2xl hover:scale-105 transition-all"
            title="Abrir Menu"
          >
            <Menu size={24} />
          </button>
        )}

        {notification && (
          <div className="fixed top-6 right-6 z-[100] animate-in slide-in-from-right duration-300">
            <div className={`px-6 py-4 rounded-2xl shadow-2xl border flex items-center gap-3 ${notification.type === 'success' ? 'bg-emerald-50 border-emerald-200 text-emerald-800 dark:bg-dracula-green/20 dark:text-dracula-green' : 'bg-rose-50 border-rose-200 text-rose-800 dark:bg-dracula-red/20 dark:text-dracula-red'}`}>
              {notification.type === 'success' ? <CheckCircle2 size={20} /> : <AlertCircle size={20} />}
              <span className="font-bold text-sm">{notification.message}</span>
            </div>
          </div>
        )}

        <div className="flex-1 overflow-y-auto p-4 md:p-10 space-y-8 transition-all duration-300">
          <header className="space-y-1">
            <h2 className="text-3xl font-extrabold tracking-tight">
              {currentView === 'form' ? 'GestĂŁo de Ativos' : currentView === 'inventory' ? 'InventĂĄrio' : 'Outlook'}
            </h2>
            <p className="text-slate-500 text-sm font-medium">Controle de equipamentos TI Cirion</p>
          </header>

          <div className="bg-white dark:bg-dracula-darker rounded-[2.5rem] shadow-2xl border border-slate-100 dark:border-dracula-current min-h-[600px] overflow-hidden">
            {currentView === 'form' && (
              <AssetForm 
                onSave={handleSaveExchange} 
                editingExchange={editingExchange} 
                onCancel={() => navTo('inventory')} 
                m365Connected={!!m365Account}
              />
            )}
            {currentView === 'inventory' && (
              <InventoryTable 
                exchanges={exchanges} 
                onDelete={handleDeleteRequest} 
                onEdit={(ex) => { setEditingExchange(ex); setCurrentView('form'); }} 
                onNotify={showNotification}
                onSignStart={setSigningExchange}
                onBulkImport={(data) => { exchanges.push(...data); loadData(); }}
                logoPref={logoPref}
              />
            )}
            {currentView === 'inbox' && (
              <MockInbox 
                emails={emails} 
                onUpdateEmails={setEmails} 
                exchanges={exchanges}
                onSignReceiver={(id, sig) => {
                  const ex = exchanges.find(e => e.id === id);
                  if(ex) { ex.status = 'completed'; ex.assinatura_colaborador = sig; apiService.save(ex); loadData(); showNotification("Termo finalizado!"); }
                }}
                logoPref={logoPref}
              />
            )}
          </div>
        </div>
      </main>

      {signingExchange && <SenderSignatureModal exchange={signingExchange} onClose={() => setSigningExchange(null)} onConfirm={handleSignSender} />}

      {itemToDelete && (
        <ConfirmationModal 
          title="Excluir Registro" 
          message="Tem certeza que deseja excluir este item permanentemente? Esta aĂ§ĂŁo nĂŁo pode ser desfeita."
          onConfirm={confirmDelete}
          onCancel={() => setItemToDelete(null)}
          isDanger
          confirmLabel="Excluir"
          confirmationKeyword="excluiragora"
        />
      )}

      {showConfigModal && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-4 bg-slate-900/90 backdrop-blur-md">
           <div className="bg-white dark:bg-dracula-bg w-full max-w-sm rounded-[2rem] p-8 border shadow-2xl">
              <h3 className="text-xl font-bold mb-6">Configurar Microsoft 365</h3>
              <div className="space-y-4">
