                  (formData[`${prefix}acessorios` as keyof AssetExchange] as string[]).includes(acc)
                    ? 'bg-emerald-500/20 text-emerald-700 dark:text-emerald-300 border-emerald-500/50 shadow-sm'
                    : 'bg-white dark:bg-dracula-bg text-slate-500 border-slate-200 dark:border-dracula-current hover:border-dracula-purple'
                }`}
              >
                <CheckSquare size={14} className={ (formData[`${prefix}acessorios` as keyof AssetExchange] as string[]).includes(acc) ? 'opacity-100 text-emerald-600 dark:text-emerald-400' : 'opacity-20' } />
                {acc}
              </button>
            ))}
          </div>
        </div>

        <div className="sm:col-span-2 pt-2">
          <label className="text-[10px] font-bold text-slate-400 uppercase flex items-center gap-1 mb-1">
             <FileText size={12}/> ObservaĂ§Ă”es ({isEntregue ? 'Entrega' : 'DevoluĂ§ĂŁo'})
          </label>
          <textarea 
            disabled={isReadOnly} 
            className="w-full p-3 rounded-xl border border-slate-200 focus:border-dracula-purple dark:border-dracula-current dark:bg-dracula-bg text-xs outline-none transition-all h-20 resize-none" 
            value={formData[`${prefix}observacoes` as keyof AssetExchange] as string} 
            onChange={e => setFormData(prev => ({...prev, [`${prefix}observacoes`]: e.target.value}))} 
            placeholder={`Notas sobre o equipamento ${isEntregue ? 'entregue' : 'devolvido'}...`}
          />
        </div>
      </div>
    </div>
  );
};

