import React, { useState, useEffect, useRef } from 'react';
import { AssetExchange, EquipmentCondition } from '../types';
import { EQUIPMENT_TYPES, BRANDS, MODELS_LIST, PROCESSORS_LIST, MEMORY_LIST, STORAGE_LIST, AD_USERS } from '../constants';
