export default AssetForm;

import { jsPDF } from 'jspdf';
import { AssetExchange, LogoPreference } from '../types';

export const generateAssetPDF = (exchange: AssetExchange, logoPref: LogoPreference = 'cirion') => {
  try {
    const doc = new jsPDF({
      orientation: 'p',
      unit: 'mm',
      format: 'a4'
    });

    // Cores extraĂ­das para o efeito 3D e visual
    const cirionBlue = "#1a5edb"; 
    const cirionShadow = "#0a3a8a"; 
    const boxBlue = "#00158a"; 
    const inkBlue = "#003087";

    const renderPage = (isEntregue: boolean) => {
      const prefix = isEntregue ? 'entregue_' : 'devolvido_';

      // 1. RenderizaĂ§ĂŁo condicional do logotipo
      if (logoPref === 'cirion') {
        const startX = 25;
        const startY = 25;
        const mainText = "CIRION";
        const subText = "TECHNOLOGIES";

        // Parte Principal
        doc.setFont("helvetica", "bold");
        doc.setFontSize(28);
        doc.setTextColor(cirionShadow);
        doc.text(mainText, startX + 0.4, startY + 0.4);
        doc.setTextColor(cirionBlue);
        doc.text(mainText, startX, startY);

        // Subtexto
        doc.setFontSize(9);
        doc.setCharSpace(1.5);
        doc.setTextColor(cirionShadow);
        doc.text(subText, startX + 0.8, startY + 7.3);
        doc.setTextColor(cirionBlue);
        doc.text(subText, startX + 0.5, startY + 7);
        doc.setCharSpace(0);
      }

      // TĂ­tulo e Checkboxes
      doc.setFontSize(11);
      doc.setTextColor(boxBlue);
      const titleText = logoPref === 'cirion' ? "DeclaraĂ§ĂŁo de Equipamento Cirion" : "DeclaraĂ§ĂŁo de Entrega de Equipamento";
      doc.text(titleText, 85, 20);

      doc.setDrawColor(boxBlue);
      doc.setLineWidth(0.3);

      // Checkbox Entrega
      doc.rect(85, 23, 3, 3);
      if (isEntregue) doc.text("x", 86, 25.5);
      doc.setFontSize(9);
      doc.text("Entrega", 90, 25.5);

      // Checkbox DevoluĂ§ĂŁo
      doc.rect(110, 23, 3, 3);
      if (!isEntregue) doc.text("x", 111, 25.5);
      doc.text("DevoluĂ§ĂŁo", 115, 25.5);

      // 2. Texto de IntroduĂ§ĂŁo
      doc.setFontSize(9);
      doc.setTextColor(0, 0, 0);
      doc.setFont("helvetica", "normal");
      doc.text("Eu, ", 20, 40);
      doc.line(26, 40.5, 95, 40.5);
      doc.setFont("helvetica", "bold");
      doc.text(exchange.colaborador_nome, 28, 40);
      doc.setFont("helvetica", "normal");
      doc.text("declaro ter recebido/devolvido o", 97, 40);
      doc.text("equipamento e acessĂłrios abaixo descritos, em perfeitas condiĂ§Ă”es de funcionamento.", 20, 45);

      // 3. Campos de Dados
      let y = 55;
      const LABEL_X = 20;
      const FIELD_X = 40;
      const BOX_WIDTH = 100;

      const drawField = (label: string, value: string, width: number = BOX_WIDTH, customX: number = FIELD_X) => {
        doc.setFont("helvetica", "bold");
        doc.setFontSize(11);
        doc.setTextColor(0, 0, 0);
        doc.text(label, LABEL_X, y + 4.5);

        doc.setDrawColor(boxBlue);
        doc.rect(customX, y, width, 6);
        doc.setFont("helvetica", "normal");
        doc.text(value || "", customX + 2, y + 4.5);
        y += 8;
      };

      drawField("Tipo:", String(exchange[`${prefix}tipo` as keyof AssetExchange]));
      drawField("Marca:", String(exchange[`${prefix}marca` as keyof AssetExchange]));
      drawField("Modelo:", String(exchange[`${prefix}modelo` as keyof AssetExchange]));
      drawField("NĂșmero de Serie / Imei:", String(exchange[`${prefix}serial` as keyof AssetExchange]), 82, 68);
      drawField("Estado:", String(exchange[`${prefix}condicao` as keyof AssetExchange]), 25);

      y += 2;
      doc.setFont("helvetica", "bold");
      doc.text("Tamanho do HD:", 20, y + 4.5);
      doc.rect(58, y, 30, 6);
      doc.setFont("helvetica", "normal");
      doc.text(String(exchange[`${prefix}armazenamento` as keyof AssetExchange]), 60, y + 4.5);
      y += 8;

      drawField("Processador:", String(exchange[`${prefix}processador` as keyof AssetExchange]), 150, 50);

      doc.setFont("helvetica", "bold");
      doc.text("MemĂłria:", 20, y + 4.5);
      doc.rect(42, y, 25, 6);
      doc.setFont("helvetica", "normal");
      doc.text(String(exchange[`${prefix}memoria` as keyof AssetExchange]), 44, y + 4.5);
      y += 15;

      // 4. Caixa de AcessĂłrios
      doc.setFontSize(12);
      doc.setFont("helvetica", "bold");
      doc.text("AcessĂłrios:", 105, y, { align: "center" });
      y += 4;

      doc.setDrawColor(boxBlue);
      doc.rect(45, y, 120, 20);

      const accessories = ["Mouse", "Teclado", "Headset", "Mochila", "DockStation", "Monitor"];
      const selectedAccs = (exchange[`${prefix}acessorios` as keyof AssetExchange] as string[]) || [];

      doc.setFontSize(10);
      doc.setFont("helvetica", "normal");
      let accX = 65;
      let accY = y + 5;

      accessories.forEach((acc, index) => {
        doc.rect(accX, accY - 2.5, 3, 3);
        if (selectedAccs.includes(acc)) doc.text("x", accX + 0.8, accY);
        doc.text(acc, accX + 5, accY);

        if (index === 2) {
          accX = 110;
          accY = y + 5;
        } else {
          accY += 6;
        }
      });

      y += 35;

      // 5. ObservaĂ§Ă”es
      doc.setFontSize(11);
      doc.setFont("helvetica", "bold");
      doc.text("Obs:", 20, y + 4.5);
      doc.rect(32, y, 150, 6);

      // ObtĂ©m o texto especĂ­fico para a pĂĄgina atual (Entrega ou DevoluĂ§ĂŁo)
      let obsText = "";
      if (isEntregue) {
        obsText = exchange.entregue_observacoes || "";
      } else {
        obsText = exchange.devolvido_observacoes || "";
      }

      // Fallback para campo antigo se os novos estiverem vazios (retrocompatibilidade)
      if (!obsText && (exchange as any).observacoes) {
        obsText = (exchange as any).observacoes;
      }

      doc.setFont("helvetica", "normal");
      doc.setFontSize(9);
      doc.text(obsText || "", 34, y + 4.5, { maxWidth: 145 });

      y += 25;

      // 6. RodapĂ© Legal
      doc.setFontSize(8);
      doc.setDrawColor(0, 0, 0);
      doc.line(20, y, 85, y);

      doc.setFont("helvetica", "bold");
      doc.text(exchange.colaborador_nome, 52.5, y - 1, { align: 'center' });

      doc.setFont("helvetica", "normal");
      const footerCompany = logoPref === 'cirion' ? "Cirion Technologies" : "nossa organizaĂ§ĂŁo";
      doc.text(`compromete-se a usar e devolver os equipamentos e acessĂłrios`, 87, y);
      y += 4;
      const footerText = `fornecidos pela empresa em perfeitas condiĂ§Ă”es e com todas as informaĂ§Ă”es, arquivos, contatos, arquivos de dados pessoais, e-mails, documentos de propriedades da ${footerCompany} e / ou qualquer uma das suas filiais, no tĂ©rmino do seu contrato de trabalho ou no final do perĂ­odo de autorizaĂ§ĂŁo, sem as alterar, modificar, copiar, transferir, no estado em que foram entregues e sempre observando o princĂ­pio da confidencialidade. Se compromete em notificar o responsĂĄvel de TI em caso de perda ou destruiĂ§ĂŁo do laptop, para que as medidas de seguranĂ§a necessĂĄrias para a proteĂ§ĂŁo de dados sejam aplicadas.`;
      const splitText = doc.splitTextToSize(footerText, 175);
      doc.text(splitText, 20, y);

      y += 30;

      // 7. Data e Assinaturas
      const date = new Date(exchange.data_troca + 'T12:00:00');
      const months = ["janeiro", "fevereiro", "marĂ§o", "abril", "maio", "junho", "julho", "agosto", "setembro", "outubro", "novembro", "dezembro"];
      const dateStr = `Data: ${date.getDate()} de ${months[date.getMonth()]} de ${date.getFullYear()}`;
      doc.setFontSize(10);
      doc.setFont("helvetica", "bold");
      doc.text(dateStr, 20, y);

      y += 25;
      doc.setDrawColor(0, 0, 0);
      doc.line(20, y, 75, y);
      doc.line(120, y, 185, y);

      doc.setFontSize(8);
      doc.setFont("helvetica", "normal");

      const tiLabel = logoPref === 'cirion' ? "TI - Cirion: Gilberto Araujo" : "ResponsĂĄvel TI: Gilberto Araujo";
      const colabLabel = logoPref === 'cirion' ? `Colaborador Cirion: ${exchange.colaborador_nome}` : `Colaborador: ${exchange.colaborador_nome}`;

      doc.text(tiLabel, 47.5, y + 4, { align: 'center' });
      doc.text(colabLabel, 152.5, y + 4, { align: 'center' });

      // Assinaturas Digitais
      doc.setFont("times", "italic");
      doc.setFontSize(18);
      doc.setTextColor(inkBlue);

      if (exchange.assinatura_ti) {
        doc.text(exchange.assinatura_ti, 47.5, y - 2, { align: 'center' });
      }

      if (exchange.assinatura_colaborador) {
        doc.text(exchange.assinatura_colaborador, 152.5, y - 2, { align: 'center' });
      }
    };

    // Gera a pĂĄgina de entrega (Sempre)
    renderPage(true);

    // SĂł gera a pĂĄgina de devoluĂ§ĂŁo se NĂO for uma operaĂ§ĂŁo apenas de entrega
    if (exchange.operationType !== 'delivery') {
      doc.addPage();
      renderPage(false);
    }

    // ConstrĂłi nome do arquivo: NOME COMPLETO_TIPO_ENTREGUE=SERIAL_DEV.=SERIAL_DD.MM.YY.pdf
    // Normaliza acentos e remove caracteres especiais
    const clean = (str: string) => str ? str.normalize("NFD").replace(/[\u0300-\u036f]/g, "").replace(/[^a-zA-Z0-9\s-]/g, '').trim().toUpperCase() : 'NA';

    const nome = clean(exchange.colaborador_nome);
    const tipo = clean(exchange.entregue_tipo || exchange.devolvido_tipo || "Equipamento");
    const serialEnt = clean(exchange.entregue_serial);
    const serialDev = exchange.operationType === 'delivery' ? 'NOVO' : clean(exchange.devolvido_serial);

    // Formata a data de YYYY-MM-DD para DD.MM.YY (usando pontos pois barras sĂŁo proibidas em nomes de arquivo)
    let dataFormatted = exchange.data_troca;
    if (exchange.data_troca && exchange.data_troca.includes('-')) {
        const [year, month, day] = exchange.data_troca.split('-');
        dataFormatted = `${day}.${month}.${year.slice(-2)}`;
    }

    const fileName = `${nome}_${tipo}_ENTREGUE=${serialEnt}_DEV.=${serialDev}_${dataFormatted}.pdf`;
    doc.save(fileName);
  } catch (error) {
    console.error("Erro ao gerar PDF:", error);
    alert("Erro ao processar o modelo do PDF.");
  }
};

import * as XLSX from 'xlsx';
import { AssetExchange, EquipmentCondition, OperationType } from '../types';

export const exportToExcel = (data: AssetExchange[]) => {
  const flattenedData = data.map(item => ({
    "ID": item.id,
    "Tipo OperaĂ§ĂŁo": item.operationType === 'delivery' ? 'Entrega (Novo)' : 'Troca',
    "Status": item.status,
    "Colaborador": item.colaborador_nome,
    "Email": item.colaborador_email,
    "Data Troca": item.data_troca,
    "Entregue Tipo": item.entregue_tipo,
    "Entregue Marca": item.entregue_marca,
    "Entregue Modelo": item.entregue_modelo,
    "Entregue Serial": item.entregue_serial,
    "Entregue Condicao": item.entregue_condicao,
    "Entregue Processador": item.entregue_processador,
    "Entregue Memoria": item.entregue_memoria,
    "Entregue HD": item.entregue_armazenamento,
    "Entregue Acessorios": item.entregue_acessorios.join(', '),
    "Obs Entrega": item.entregue_observacoes,
    "Devolvido Tipo": item.devolvido_tipo,
    "Devolvido Marca": item.devolvido_marca,
    "Devolvido Modelo": item.devolvido_modelo,
    "Devolvido Serial": item.devolvido_serial,
    "Devolvido Condicao": item.devolvido_condicao,
    "Devolvido Processador": item.devolvido_processador,
    "Devolvido Memoria": item.devolvido_memoria,
    "Devolvido HD": item.devolvido_armazenamento,
    "Devolvido Acessorios": item.devolvido_acessorios.join(', '),
    "Obs DevoluĂ§ĂŁo": item.devolvido_observacoes,
    "Assinatura TI": item.assinatura_ti || "",
    "Assinatura Colaborador": item.assinatura_colaborador || ""
  }));

  const worksheet = XLSX.utils.json_to_sheet(flattenedData);

  // Adiciona Filtros AutomĂĄticos em todas as colunas
  if (worksheet['!ref']) {
    const range = XLSX.utils.decode_range(worksheet['!ref']);
    worksheet['!autofilter'] = { ref: XLSX.utils.encode_range(range) };
  }

  // Define larguras de coluna para melhor legibilidade
  worksheet['!cols'] = [
    { wch: 12 }, // ID
    { wch: 15 }, // Tipo Op
    { wch: 15 }, // Status
    { wch: 30 }, // Colaborador
    { wch: 35 }, // Email
    { wch: 12 }, // Data Troca
    { wch: 15 }, // Entregue Tipo
    { wch: 15 }, // Entregue Marca
    { wch: 20 }, // Entregue Modelo
    { wch: 20 }, // Entregue Serial
    { wch: 15 }, // Entregue Condicao
    { wch: 40 }, // Entregue Processador
    { wch: 15 }, // Entregue Memoria
    { wch: 15 }, // Entregue HD
    { wch: 40 }, // Entregue Acessorios
    { wch: 30 }, // Obs Entrega
    { wch: 15 }, // Devolvido Tipo
    { wch: 15 }, // Devolvido Marca
    { wch: 20 }, // Devolvido Modelo
    { wch: 20 }, // Devolvido Serial
    { wch: 15 }, // Devolvido Condicao
    { wch: 40 }, // Devolvido Processador
    { wch: 15 }, // Devolvido Memoria
    { wch: 15 }, // Devolvido HD
    { wch: 40 }, // Devolvido Acessorios
    { wch: 30 }, // Obs DevoluĂ§ĂŁo
    { wch: 25 }, // Assinatura TI
    { wch: 25 }, // Assinatura Colaborador
  ];

  const workbook = XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(workbook, worksheet, "InventĂĄrio de Ativos");

  const fileName = `AssetFlow_Export_${new Date().toISOString().split('T')[0]}.xlsx`;
  XLSX.writeFile(workbook, fileName);
};

export const importFromExcel = (file: File): Promise<AssetExchange[]> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const data = new Uint8Array(e.target?.result as ArrayBuffer);
        const workbook = XLSX.read(data, { type: 'array' });
        const firstSheetName = workbook.SheetNames[0];
        const worksheet = workbook.Sheets[firstSheetName];
        const jsonData = XLSX.utils.sheet_to_json(worksheet) as any[];

        const importedExchanges: AssetExchange[] = jsonData.map(row => {
          // Determina o tipo de operaĂ§ĂŁo baseado no valor ou padrĂŁo
          let opType: OperationType = 'exchange';
          const rowOp = row["Tipo OperaĂ§ĂŁo"];
          if (rowOp === 'Entrega (Novo)' || rowOp === 'delivery') opType = 'delivery';

          return {
            id: String(row["ID"] || Math.random().toString(36).substr(2, 9).toUpperCase()),
            operationType: opType,
            status: row["Status"] || 'draft',
            timestamp: Date.now(),
            colaborador_nome: String(row["Colaborador"] || ""),
            colaborador_email: String(row["Email"] || ""),
            data_troca: String(row["Data Troca"] || new Date().toISOString().split('T')[0]),
            // Mapeia colunas novas ou cai no fallback da coluna antiga 'Obs'
            entregue_observacoes: String(row["Obs Entrega"] || row["Obs"] || ""), 
            devolvido_observacoes: String(row["Obs DevoluĂ§ĂŁo"] || ""),
            entregue_tipo: String(row["Entregue Tipo"] || ""),
            entregue_marca: String(row["Entregue Marca"] || ""),
            entregue_modelo: String(row["Entregue Modelo"] || ""),
            entregue_serial: String(row["Entregue Serial"] || ""),
            entregue_processador: String(row["Entregue Processador"] || ""),
            entregue_condicao: row["Entregue Condicao"] as EquipmentCondition,
            entregue_memoria: String(row["Entregue Memoria"] || ""),
            entregue_armazenamento: String(row["Entregue HD"] || ""),
            entregue_acessorios: row["Entregue Acessorios"] ? String(row["Entregue Acessorios"]).split(', ') : [],
            devolvido_tipo: String(row["Devolvido Tipo"] || ""),
            devolvido_marca: String(row["Devolvido Marca"] || ""),
            devolvido_modelo: String(row["Devolvido Modelo"] || ""),
            devolvido_serial: String(row["Devolvido Serial"] || ""),
            devolvido_processador: String(row["Devolvido Processador"] || ""),
            devolvido_condicao: row["Devolvido Condicao"] as EquipmentCondition,
            devolvido_memoria: String(row["Devolvido Memoria"] || ""),
            devolvido_armazenamento: String(row["Devolvido HD"] || ""),
            devolvido_acessorios: row["Devolvido Acessorios"] ? String(row["Devolvido Acessorios"]).split(', ') : [],
            assinatura_ti: row["Assinatura TI"],
            assinatura_colaborador: row["Assinatura Colaborador"]
          };
        });

        resolve(importedExchanges);
      } catch (err) {
        reject(err);
      }
    };
    reader.onerror = reject;
    reader.readAsArrayBuffer(file);
  });
};

